import{_ as a,c as e,o as m,b as t}from"./app.6039188d.js";const b='{"title":"\u0410\u0444\u043E\u0440\u0438\u0437\u043C 3","description":"","frontmatter":{"title":"\u0410\u0444\u043E\u0440\u0438\u0437\u043C 3","subtitle":"\u0428\u0438\u0432\u0430 \u0441\u0443\u0442\u0440\u0430 \u0432\u0438\u043C\u0430\u0440\u0448\u0438\u043D\u0438. \u0413\u043B\u0430\u0432\u0430 2.","tags":"vim-2","date":"2021-02-08T00:00:00.000Z"},"headers":[],"relativePath":"texts/shiva-sutra-vimarshini/2/3/index.md"}',r={},i=t('<div class="stanza"><a href="#s2.3" id="s2.3" class="num">2.3</a><div class="sans"><p>\u0908\u0926\u0943\u0936\u0938\u093E\u0927\u0915\u0938\u093E\u0927\u094D\u092F\u0938\u094D\u092F \u092E\u0928\u094D\u0924\u094D\u0930\u0938\u094D\u092F \u092A\u0942\u0930\u094D\u0935\u094B\u092A\u0915\u094D\u0937\u093F\u092A\u094D\u0924\u0902 \u0935\u0940\u0930\u094D\u092F\u0902 \u0932\u0915\u094D\u0937\u092F\u0924\u093F\u2014</p><blockquote><p><strong>\u0935\u093F\u0926\u094D\u092F\u093E\u0936\u0930\u0940\u0930\u0938\u0924\u094D\u0924\u093E \u092E\u0928\u094D\u0924\u094D\u0930\u0930\u0939\u0938\u094D\u092F\u092E\u094D\u0965\u0969\u0965</strong></p></blockquote><p>\u0935\u093F\u0926\u094D\u092F\u093E \u092A\u0930\u093E\u0926\u094D\u0935\u092F\u092A\u094D\u0930\u0925\u093E \u0936\u0930\u0940\u0930\u0902 \u0938\u094D\u0935\u0930\u0942\u092A\u0902 \u092F\u0938\u094D\u092F \u0938 \u0935\u093F\u0926\u094D\u092F\u093E\u0936\u0930\u0940\u0930\u094B \u092D\u0917\u0935\u093E\u0928\u094D \u0936\u092C\u094D\u0926\u0930\u093E\u0936\u093F\u0938\u094D\u0924\u0938\u094D\u092F \u092F\u093E \u0938\u0924\u094D\u0924\u093E\u0936\u0947\u0937\u0935\u093F\u0936\u094D\u0935\u093E\u092D\u0947\u0926\u092E\u092F\u092A\u0942\u0930\u094D\u0923\u093E\u0939\u0902\u0935\u093F\u092E\u0930\u094D\u0936\u0928\u093E\u0924\u094D\u092E\u093E \u0938\u094D\u092B\u0941\u0930\u0924\u094D\u0924\u093E \u0938\u093E \u092E\u0928\u094D\u0924\u094D\u0930\u093E\u0923\u093E\u0902 \u0930\u0939\u0938\u094D\u092F\u092E\u0941\u092A\u0928\u093F\u0937\u0924\u094D\u0964 \u092F\u0926\u0941\u0915\u094D\u0924\u0902 \u0936\u094D\u0930\u0940\u0924\u0928\u094D\u0924\u094D\u0930\u0938\u0926\u094D\u092D\u093E\u0935\u0947</p><blockquote><p>\u0938\u0930\u094D\u0935\u0947 \u0935\u0930\u094D\u0923\u093E\u0924\u094D\u092E\u0915\u093E \u092E\u0928\u094D\u0924\u094D\u0930\u093E\u0938\u094D\u0924\u0947 \u091A \u0936\u0915\u094D\u0924\u094D\u092F\u093E\u0924\u094D\u092E\u0915\u093E\u0903 \u092A\u094D\u0930\u093F\u092F\u0947\u0964<br> \u0936\u0915\u094D\u0924\u093F\u0938\u094D\u0924\u0941 \u092E\u093E\u0924\u0943\u0915\u093E \u091C\u094D\u091E\u0947\u092F\u093E \u0938\u093E \u091A \u091C\u094D\u091E\u0947\u092F\u093E \u0936\u093F\u0935\u093E\u0924\u094D\u092E\u093F\u0915\u093E\u0965</p></blockquote><p>\u0907\u0924\u093F\u0964 \u0924\u0924\u094D\u0930\u0948\u0935 \u091A\u093E\u092F\u092E\u0930\u094D\u0925\u094B\u093D\u0924\u093F\u0930\u0939\u0938\u094D\u092F\u094B\u093D\u092A\u093F \u0935\u093F\u0924\u0924\u094D\u092F \u0938\u094D\u092B\u0941\u091F\u0940\u0915\u0943\u0924\u0903\u0964 \u0924\u0925\u093E \u091A</p><blockquote><p>\u0928 \u091C\u093E\u0928\u0928\u094D\u0924\u093F \u0917\u0941\u0930\u0941\u0902 \u0926\u0947\u0935\u0902 \u0936\u093E\u0938\u094D\u0924\u094D\u0930\u094B\u0915\u094D\u0924\u093E\u0928\u094D\u0938\u092E\u092F\u093E\u0902\u0938\u094D\u0924\u0925\u093E\u0964<br> \u0926\u092E\u094D\u092D\u0915\u094C\u091F\u093F\u0932\u094D\u092F\u0928\u093F\u0930\u0924\u093E \u0932\u094C\u0932\u094D\u092F\u093E\u0930\u094D\u0925\u093E\u0903 \u0915\u094D\u0930\u093F\u092F\u092F\u094B\u091C\u094D\u091D\u093F\u0924\u093E\u0903\u0965<br> \u0905\u0938\u094D\u092E\u093E\u0924\u094D\u0924\u0941 \u0915\u093E\u0930\u0923\u093E\u0926\u094D\u0926\u0947\u0935\u093F \u092E\u092F\u093E \u0935\u0940\u0930\u094D\u092F\u0902 \u092A\u094D\u0930\u0917\u094B\u092A\u093F\u0924\u092E\u094D\u0964<br> \u0924\u0947\u0928 \u0917\u0941\u092A\u094D\u0924\u0947\u0928 \u0924\u0947 \u0917\u0941\u092A\u094D\u0924\u093E\u0903 \u0936\u0947\u0937\u093E \u0935\u0930\u094D\u0923\u093E\u0938\u094D\u0924\u0941 \u0915\u0947\u0935\u0932\u093E\u0903\u0965</p></blockquote><p>\u0907\u0924\u093F \u092A\u0940\u0920\u093F\u0915\u093E\u092C\u0928\u094D\u0927\u0902 \u0915\u0943\u0924\u094D\u0935\u093E</p><blockquote><p>\u092F\u093E \u0938\u093E \u0924\u0941 \u092E\u093E\u0924\u0943\u0915\u093E \u0926\u0947\u0935\u093F \u092A\u0930\u0924\u0947\u091C\u0903\u0938\u092E\u0928\u094D\u0935\u093F\u0924\u093E\u0964<br> \u0924\u092F\u093E \u0935\u094D\u092F\u093E\u092A\u094D\u0924\u092E\u093F\u0926\u0902 \u0935\u093F\u0936\u094D\u0935\u0902 \u0938\u092C\u094D\u0930\u0939\u094D\u092E\u092D\u0941\u0935\u0928\u093E\u0928\u094D\u0924\u0915\u092E\u094D\u0965<br> \u0924\u0924\u094D\u0930\u0938\u094D\u0925\u0902 \u091A \u0938\u0926\u093E \u0926\u0947\u0935\u093F \u0935\u094D\u092F\u093E\u092A\u093F\u0924\u0902 \u091A \u0938\u0941\u0930\u093E\u0930\u094D\u091A\u093F\u0924\u0947\u0964<br> \u0905\u0935\u0930\u094D\u0923\u0938\u094D\u0925\u094B \u092F\u0925\u093E \u0935\u0930\u094D\u0923\u0903 \u0938\u094D\u0925\u093F\u0924\u0903 \u0938\u0930\u094D\u0935\u0917\u0924\u0903 \u092A\u094D\u0930\u093F\u092F\u0947\u0965<br> \u0924\u0925\u093E\u0939\u0902 \u0915\u0925\u092F\u093F\u0937\u094D\u092F\u093E\u092E\u093F \u0928\u093F\u0930\u094D\u0923\u092F\u093E\u0930\u094D\u0925\u0902 \u0938\u094D\u092B\u0941\u091F\u0902 \u0924\u0935\u0964</p></blockquote><p>\u0907\u0924\u094D\u092F\u0941\u092A\u0915\u094D\u0930\u092E\u094D\u092F</p><blockquote><p>\u092F\u093E \u0938\u093E \u0936\u0915\u094D\u0924\u093F\u0903 \u092A\u0930\u093E \u0938\u0942\u0915\u094D\u0937\u094D\u092E\u093E \u0928\u093F\u0930\u093E\u091A\u093E\u0930\u0947\u0924\u093F \u0915\u0940\u0930\u094D\u0924\u093F\u0924\u093E\u0965<br> \u0939\u0943\u0926\u094D\u092C\u093F\u0928\u094D\u0926\u0941\u0902 \u0935\u0947\u0937\u094D\u091F\u092F\u093F\u0924\u094D\u0935\u093E\u0928\u094D\u0924\u0903 \u0938\u0941\u0937\u0941\u092A\u094D\u0924\u092D\u0941\u091C\u0917\u093E\u0915\u0943\u0924\u093F\u0903\u0964<br> \u0924\u0924\u094D\u0930 \u0938\u0941\u092A\u094D\u0924\u093E \u092E\u0939\u093E\u092D\u093E\u0917\u0947 \u0928 \u0915\u093F\u091E\u094D\u091A\u093F\u0928\u094D\u092E\u0928\u094D\u092F\u0924 \u0909\u092E\u0947\u0965<br> \u091A\u0928\u094D\u0926\u094D\u0930\u093E\u0917\u094D\u0928\u093F\u0930\u0935\u093F\u0928\u0915\u094D\u0937\u0924\u094D\u0930\u0948\u0930\u094D\u092D\u0941\u0935\u0928\u093E\u0928\u093F \u091A\u0924\u0941\u0930\u094D\u0926\u0936\u0964<br> \u0915\u094D\u0937\u093F\u092A\u094D\u0924\u094D\u0935\u094B\u0926\u0930\u0947 \u0924\u0941 \u092F\u093E \u0926\u0947\u0935\u0940 \u0935\u093F\u0937\u092E\u0942\u0922\u0947\u0935 \u0938\u093E \u0917\u0924\u093E\u0965<br> \u092A\u094D\u0930\u092C\u0941\u0926\u094D\u0927\u093E \u0938\u093E \u0928\u093F\u0928\u093E\u0926\u0947\u0928 \u092A\u0930\u0947\u0923 \u091C\u094D\u091E\u093E\u0928\u0930\u0942\u092A\u093F\u0923\u093E\u0964<br> \u092E\u0925\u093F\u0924\u093E \u091A\u094B\u0926\u0930\u0938\u094D\u0925\u0947\u0928 \u0935\u093F\u0928\u094D\u0926\u0941\u0928\u093E \u0935\u0930\u0935\u0930\u094D\u0923\u093F\u0928\u093F\u0965<br> \u0924\u093E\u0935\u0926\u094D\u0935\u0948 \u092D\u094D\u0930\u092E\u0935\u0947\u0917\u0947\u0928 \u092E\u0925\u0928\u0902 \u0936\u0915\u094D\u0924\u093F\u0935\u093F\u0917\u094D\u0930\u0939\u0947\u0964<br> \u092D\u0947\u0926\u093E\u0924\u094D\u0924\u0941 \u092A\u094D\u0930\u0925\u092E\u094B\u0924\u094D\u092A\u0928\u094D\u0928\u093E \u0935\u093F\u0928\u094D\u0926\u0935\u0938\u094D\u0924\u0947\u093D\u0924\u093F\u0935\u0930\u094D\u091A\u0938\u0903\u0965<br> \u0909\u0924\u094D\u0925\u093F\u0924\u093E \u0924\u0941 \u092F\u0926\u093E \u0924\u0947\u0928 \u0915\u0932\u093E \u0938\u0942\u0915\u094D\u0937\u094D\u092E\u093E \u0924\u0941 \u0915\u0941\u0923\u094D\u0921\u0932\u0940\u0964<br> \u091A\u0924\u0941\u0937\u094D\u0915\u0932\u092E\u092F\u094B \u0935\u093F\u0928\u094D\u0926\u0941\u0903 \u0936\u0915\u094D\u0924\u0947\u0930\u0941\u0926\u0930\u0917\u0903 \u092A\u094D\u0930\u092D\u0941\u0903\u0965<br> \u092E\u0925\u094D\u092F\u092E\u0928\u094D\u0925\u0928\u092F\u094B\u0917\u0947\u0928 \u090B\u091C\u0941\u0924\u094D\u0935\u0902 \u091C\u093E\u092F\u0924\u0947 \u092A\u094D\u0930\u093F\u092F\u0947\u0964<br> \u091C\u094D\u092F\u0947\u0937\u094D\u0920\u093E\u0936\u0915\u094D\u0924\u093F\u0903 \u0938\u094D\u092E\u0943\u0924\u093E \u0938\u093E \u0924\u0941 \u0935\u093F\u0928\u094D\u0926\u0941\u0926\u094D\u0935\u092F\u0938\u0941\u092E\u0927\u094D\u092F\u0917\u093E\u0965<br> \u0935\u093F\u0928\u094D\u0926\u0941\u0928\u093E \u0915\u094D\u0937\u094B\u092D\u092E\u093E\u092F\u093E\u0924\u093E \u0930\u0947\u0916\u0948\u0935\u093E\u092E\u0943\u0924\u0915\u0941\u0923\u094D\u0921\u0932\u0940\u0964<br> \u0930\u0947\u0916\u093F\u0923\u0940 \u0928\u093E\u092E \u0938\u093E \u091C\u094D\u091E\u0947\u092F\u093E \u0909\u092D\u094C \u0935\u093F\u0928\u094D\u0926\u0942 \u092F\u0926\u0928\u094D\u0924\u0917\u094C\u0965<br> \u0924\u094D\u0930\u093F\u092A\u0925\u093E \u0938\u093E \u0938\u092E\u093E\u0916\u094D\u092F\u093E\u0924\u093E \u0930\u094C\u0926\u094D\u0930\u0940 \u0928\u093E\u092E\u094D\u0928\u093E \u0924\u0941 \u0917\u0940\u092F\u0924\u0947\u0964<br> \u0930\u094B\u0927\u093F\u0928\u0940 \u0938\u093E \u0938\u092E\u0941\u0926\u094D\u0926\u093F\u0937\u094D\u091F\u093E \u092E\u094B\u0915\u094D\u0937\u092E\u093E\u0930\u094D\u0917\u0928\u093F\u0930\u094B\u0927\u0928\u093E\u0924\u094D\u0965<br> \u0936\u0936\u093E\u0919\u094D\u0915\u0936\u0915\u0932\u093E\u0915\u093E\u0930\u093E \u0905\u092E\u094D\u092C\u093F\u0915\u093E \u091A\u093E\u0930\u094D\u0927\u091A\u0928\u094D\u0926\u094D\u0930\u093F\u0915\u093E\u0964<br> \u090F\u0915\u0948\u0935\u0947\u0924\u094D\u0925\u0902 \u092A\u0930\u093E \u0936\u0915\u094D\u0924\u093F\u0938\u094D\u0924\u094D\u0930\u093F\u0927\u093E \u0938\u093E \u0924\u0941 \u092A\u094D\u0930\u091C\u093E\u092F\u0924\u0947\u0965<br> \u0906\u092D\u094D\u092F\u094B \u092F\u0941\u0915\u094D\u0924\u0935\u093F\u092F\u0941\u0915\u094D\u0924\u093E\u092D\u094D\u092F\u0903 \u0938\u091E\u094D\u091C\u093E\u0924\u094B \u0928\u0935\u0935\u0930\u094D\u0917\u0915\u0903\u0964<br> \u0928\u0935\u0927\u093E \u091A \u0938\u094D\u092E\u0943\u0924\u093E \u0938\u093E \u0924\u0941 \u0928\u0935\u0935\u0930\u094D\u0917\u094B\u092A\u0932\u0915\u094D\u0937\u093F\u0924\u093E\u0965<br> \u092A\u091E\u094D\u091A\u092E\u0928\u094D\u0924\u094D\u0930\u0917\u0924\u093E \u0926\u0947\u0935\u093F \u0938\u0926\u094D\u092F \u0906\u0926\u093F\u0930\u0928\u0941\u0915\u094D\u0930\u092E\u093E\u0924\u094D\u0964<br> \u0924\u0947\u0928 \u092A\u091E\u094D\u091A\u0935\u093F\u0927\u093E \u092A\u094D\u0930\u094B\u0915\u094D\u0924\u093E \u091C\u094D\u091E\u093E\u0924\u0935\u094D\u092F\u093E \u0938\u0941\u0930\u0928\u093E\u092F\u093F\u0915\u0947\u0965<br> \u0938\u094D\u0935\u0930\u0926\u094D\u0935\u093E\u0926\u0936\u0917\u093E \u0926\u0947\u0935\u093F \u0926\u094D\u0935\u093E\u0926\u0936\u0938\u094D\u0925\u093E \u0909\u0926\u093E\u0939\u0943\u0924\u093E\u0964<br> \u0905\u0915\u093E\u0930\u093E\u0926\u093F\u0915\u094D\u0937\u0915\u093E\u0930\u093E\u0928\u094D\u0924\u093E \u0938\u094D\u0925\u093F\u0924\u093E \u092A\u091E\u094D\u091A\u093E\u0936\u0924\u093E \u092D\u093F\u0926\u093E\u0965<br> \u0939\u0943\u0924\u094D\u0938\u094D\u0925\u093E \u090F\u0915\u093E\u0923\u0935\u093E \u092A\u094D\u0930\u094B\u0915\u094D\u0924\u093E \u0915\u0923\u094D\u0920\u0947 \u092A\u094D\u0930\u094B\u0915\u094D\u0924\u093E \u0926\u094D\u0935\u093F\u0924\u0940\u092F\u0915\u093E\u0964<br> \u0924\u094D\u0930\u093F\u0930\u093E\u0923\u0935\u093E \u0924\u0941 \u091C\u094D\u091E\u093E\u0924\u0935\u094D\u092F\u093E \u091C\u093F\u0939\u094D\u0935\u093E\u092E\u0942\u0932\u0947 \u0938\u0926\u093E \u0938\u094D\u0925\u093F\u0924\u093E\u0965<br> \u091C\u093F\u0939\u094D\u0935\u093E\u0917\u094D\u0930\u0947 \u0935\u0930\u094D\u0923\u0928\u093F\u0937\u094D\u092A\u0924\u094D\u0924\u093F\u0930\u094D\u092D\u0935\u0924\u094D\u092F\u0924\u094D\u0930 \u0928 \u0938\u0902\u0936\u092F\u0903\u0964<br> \u090F\u0935\u0902 \u0936\u092C\u094D\u0926\u0938\u094D\u092F \u0928\u093F\u0937\u094D\u092A\u0924\u094D\u0924\u093F\u0903 \u0936\u092C\u094D\u0926\u0935\u094D\u092F\u093E\u092A\u094D\u0924\u0902 \u091A\u0930\u093E\u091A\u0930\u092E\u094D\u0965</p></blockquote><p>\u0907\u0924\u094D\u092F\u093E\u0926\u093F\u0928\u093E \u0917\u094D\u0930\u0928\u094D\u0925\u0947\u0928 \u092A\u0930\u092D\u0948\u0930\u0935\u0940\u092F\u092A\u0930\u093E\u0935\u093E\u0915\u094D\u0936\u0915\u094D\u0924\u094D\u092F\u093E\u0924\u094D\u092E\u0915\u092E\u093E\u0924\u0943\u0915\u093E\u0924 \u090F\u0935 \u091C\u094D\u092F\u0947\u0937\u094D\u0920\u093E\u0930\u094C\u0926\u094D\u0930\u094D\u092F\u092E\u094D\u092C\u093E\u0916\u094D\u092F\u0936\u0915\u094D\u0924\u093F\u092A\u094D\u0930\u0938\u0930\u0938\u092E\u094D\u092D\u0947\u0926\u0935\u0948\u091A\u093F\u0924\u094D\u0930\u094D\u092F\u0947\u0923 \u0938\u0930\u094D\u0935\u0935\u0930\u094D\u0923\u094B\u0926\u092F\u0938\u094D\u092F\u094B\u0915\u094D\u0924\u0924\u094D\u0935\u093E\u0926\u094D\u0935\u0930\u094D\u0923\u0938\u0919\u094D\u0918\u091F\u094D\u091F\u0928\u093E\u0936\u0930\u0940\u0930\u093E\u0923\u093E\u0902 \u092E\u0928\u094D\u0924\u094D\u0930\u093E\u0923\u093E\u0902 \u0938\u0948\u0935 \u092D\u0917\u0935\u0924\u0940 \u0935\u094D\u092F\u093E\u0916\u094D\u092F\u093E\u0924\u0930\u0942\u092A\u093E \u0935\u093F\u0926\u094D\u092F\u093E\u0936\u0930\u0940\u0930\u0938\u0924\u094D\u0924\u093E \u0930\u0939\u0938\u094D\u092F\u092E\u093F\u0924\u093F \u092A\u094D\u0930\u0926\u0930\u094D\u0936\u093F\u0924\u092E\u094D\u0964 \u092A\u094D\u0930\u0924\u094D\u092F\u093E\u0917\u092E\u0902 \u091A \u092E\u093E\u0924\u0943\u0915\u093E\u092E\u093E\u0932\u093F\u0928\u0940\u092A\u094D\u0930\u0938\u094D\u0924\u093E\u0930\u092A\u0942\u0930\u094D\u0935\u0915\u0902 \u092E\u0928\u094D\u0924\u094D\u0930\u094B\u0926\u094D\u0927\u093E\u0930\u0915\u0925\u0928\u0938\u094D\u092F\u093E\u092F\u092E\u0947\u0935\u093E\u0936\u092F\u0903\u0964 \u0930\u0939\u0938\u094D\u092F\u093E\u0917\u092E\u0938\u093E\u0930\u0938\u0919\u094D\u0917\u094D\u0930\u0939\u0930\u0942\u092A\u0924\u094D\u0935\u093E\u091A\u094D\u091B\u093F\u0935\u0938\u0942\u0924\u094D\u0930\u093E\u0923\u093E\u092E\u093E\u0917\u092E\u0938\u0902\u0935\u093E\u0926\u0947 \u092D\u0930\u094B\u093D\u0938\u094D\u092E\u093E\u092D\u093F\u0903 \u0915\u0943\u0924 \u0907\u0924\u093F \u0928\u093E\u0938\u094D\u092E\u092D\u094D\u092F\u092E\u0938\u0942\u092F\u093F\u0924\u0935\u094D\u092F\u092E\u094D\u0964 \u090F\u0935\u092E\u092A\u093F \u0938\u0902\u0935\u093E\u0926\u093F\u0924 \u0906\u0917\u092E\u0947 \u092F\u0926\u093F \u0930\u0939\u0938\u094D\u092F\u093E\u0930\u094D\u0925\u094B \u0928 \u092C\u0941\u0926\u094D\u0927\u094D\u092F\u0924\u0947 \u0924\u0938\u094D\u092E\u093E\u0924\u094D\u0938\u0926\u094D\u0917\u0941\u0930\u0941\u0938\u092A\u0930\u094D\u092F\u093E \u0915\u093E\u0930\u094D\u092F\u093E\u0964 \u090F\u0937 \u091A \u0938\u0942\u0924\u094D\u0930\u093E\u0930\u094D\u0925\u0903</p><blockquote><p>\u0924\u0926\u093E\u0915\u094D\u0930\u092E\u094D\u092F \u092C\u0932\u0902 \u092E\u0928\u094D\u0924\u094D\u0930\u093E\u0903...\u0964</p></blockquote><p>\u0907\u0924\u094D\u092F\u0928\u0947\u0928 \u0915\u093E\u0930\u093F\u0915\u093E\u0926\u094D\u0935\u092F\u0947\u0928 \u0938\u094D\u092A\u0928\u094D\u0926\u0947 \u0926\u0930\u094D\u0936\u093F\u0924\u0903\u0965\u0969\u0965</p></div><hr><div class="trans"><p>\u012Ad\u1E5B\u015Bas\u0101dhakas\u0101dhyasya mantrasya p\u016Brvopak\u1E63ipta\u1E41 v\u012Brya\u1E41 lak\u1E63ayati\u2014</p><blockquote><p><strong>Vidy\u0101\u015Bar\u012Brasatt\u0101 mantrarahasyam||3||</strong></p></blockquote><p>Vidy\u0101 par\u0101dvayaprath\u0101 \u015Bar\u012Bra\u1E41 svar\u016Bpa\u1E41 yasya sa vidy\u0101\u015Bar\u012Bro bhagav\u0101n \u015Babdar\u0101\u015Bistasya y\u0101 satt\u0101\u015Be\u1E63avi\u015Bv\u0101bhedamayap\u016Br\u1E47\u0101ha\u1E41vimar\u015Ban\u0101tm\u0101 sphuratt\u0101 s\u0101 mantr\u0101\u1E47\u0101\u1E41 rahasyamupani\u1E63at| Yadukta\u1E41 \u015Br\u012Btantrasadbh\u0101ve</p><blockquote><p>Sarve var\u1E47\u0101tmak\u0101 mantr\u0101ste ca \u015Bakty\u0101tmak\u0101\u1E25 priye|<br> \u015Aaktistu m\u0101t\u1E5Bk\u0101 j\xF1ey\u0101 s\u0101 ca j\xF1ey\u0101 \u015Biv\u0101tmik\u0101||</p></blockquote><p>iti| Tatraiva c\u0101yamartho&#39;tirahasyo&#39;pi vitatya sphu\u1E6D\u012Bk\u1E5Bta\u1E25| Tath\u0101 ca</p><blockquote><p>Na j\u0101nanti guru\u1E41 deva\u1E41 \u015B\u0101strokt\u0101nsamay\u0101\u1E41stath\u0101|<br> Dambhakau\u1E6Dilyanirat\u0101 lauly\u0101rth\u0101\u1E25 kriyayojjhit\u0101\u1E25||<br> Asm\u0101ttu k\u0101ra\u1E47\u0101ddevi may\u0101 v\u012Brya\u1E41 pragopitam|<br> Tena guptena te gupt\u0101\u1E25 \u015Be\u1E63\u0101 var\u1E47\u0101stu keval\u0101\u1E25||</p></blockquote><p>iti p\u012B\u1E6Dhik\u0101bandha\u1E41 k\u1E5Btv\u0101</p><blockquote><p>Y\u0101 s\u0101 tu m\u0101t\u1E5Bk\u0101 devi parateja\u1E25samanvit\u0101|<br> Tay\u0101 vy\u0101ptamida\u1E41 vi\u015Bva\u1E41 sabrahmabhuvan\u0101ntakam||<br> Tatrastha\u1E41 ca sad\u0101 devi vy\u0101pita\u1E41 ca sur\u0101rcite|<br> Avar\u1E47astho yath\u0101 var\u1E47a\u1E25 sthita\u1E25 sarvagata\u1E25 priye||<br> Tath\u0101ha\u1E41 kathayi\u1E63y\u0101mi nir\u1E47ay\u0101rtha\u1E41 sphu\u1E6Da\u1E41 tava|</p></blockquote><p>ityupakramya</p><blockquote><p>Y\u0101 s\u0101 \u015Bakti\u1E25 par\u0101 s\u016Bk\u1E63m\u0101 nir\u0101c\u0101reti k\u012Brtit\u0101||<br> H\u1E5Bdbindu\u1E41 ve\u1E63\u1E6Dayitv\u0101nta\u1E25 su\u1E63uptabhujag\u0101k\u1E5Bti\u1E25|<br> Tatra supt\u0101 mah\u0101bh\u0101ge na ki\xF1cinmanyata ume||<br> Candr\u0101gniravinak\u1E63atrairbhuvan\u0101ni caturda\u015Ba|<br> K\u1E63iptvodare tu y\u0101 dev\u012B vi\u1E63am\u016B\u1E0Dheva s\u0101 gat\u0101||<br> Prabuddh\u0101 s\u0101 nin\u0101dena pare\u1E47a j\xF1\u0101nar\u016Bpi\u1E47\u0101|<br> Mathit\u0101 codarasthena vindun\u0101 varavar\u1E47ini||<br> T\u0101vadvai bhramavegena mathana\u1E41 \u015Baktivigrahe|<br> Bhed\u0101ttu prathamotpann\u0101 vindavaste&#39;tivarcasa\u1E25||<br> Utthit\u0101 tu yad\u0101 tena kal\u0101 s\u016Bk\u1E63m\u0101 tu ku\u1E47\u1E0Dal\u012B|<br> Catu\u1E63kalamayo vindu\u1E25 \u015Bakterudaraga\u1E25 prabhu\u1E25||<br> Mathyamanthanayogena \u1E5Bjutva\u1E41 j\u0101yate priye|<br> Jye\u1E63\u1E6Dh\u0101\u015Bakti\u1E25 sm\u1E5Bt\u0101 s\u0101 tu vindudvayasumadhyag\u0101||<br> Vindun\u0101 k\u1E63obham\u0101y\u0101t\u0101 rekhaiv\u0101m\u1E5Btaku\u1E47\u1E0Dal\u012B|<br> Rekhi\u1E47\u012B n\u0101ma s\u0101 j\xF1ey\u0101 ubhau vind\u016B yadantagau||<br> Tripath\u0101 s\u0101 sam\u0101khy\u0101t\u0101 raudr\u012B n\u0101mn\u0101 tu g\u012Byate|<br> Rodhin\u012B s\u0101 samuddi\u1E63\u1E6D\u0101 mok\u1E63am\u0101rganirodhan\u0101t||<br> \u015Aa\u015B\u0101\u1E45ka\u015Bakal\u0101k\u0101r\u0101 ambik\u0101 c\u0101rdhacandrik\u0101|<br> Ekaivettha\u1E41 par\u0101 \u015Baktistridh\u0101 s\u0101 tu praj\u0101yate||<br> \u0100bhyo yuktaviyukt\u0101bhya\u1E25 sa\xF1j\u0101to navavargaka\u1E25|<br> Navadh\u0101 ca sm\u1E5Bt\u0101 s\u0101 tu navavargopalak\u1E63it\u0101||<br> Pa\xF1camantragat\u0101 devi sadya \u0101diranukram\u0101t|<br> Tena pa\xF1cavidh\u0101 prokt\u0101 j\xF1\u0101tavy\u0101 suran\u0101yike||<br> Svaradv\u0101da\u015Bag\u0101 devi dv\u0101da\u015Basth\u0101 ud\u0101h\u1E5Bt\u0101|<br> Ak\u0101r\u0101dik\u1E63ak\u0101r\u0101nt\u0101 sthit\u0101 pa\xF1c\u0101\u015Bat\u0101 bhid\u0101||<br> H\u1E5Btsth\u0101 ek\u0101\u1E47av\u0101 prokt\u0101 ka\u1E47\u1E6Dhe prokt\u0101 dvit\u012Byak\u0101|<br> Trir\u0101\u1E47av\u0101 tu j\xF1\u0101tavy\u0101 jihv\u0101m\u016Ble sad\u0101 sthit\u0101||<br> Jihv\u0101gre var\u1E47ani\u1E63pattirbhavatyatra na sa\u1E41\u015Baya\u1E25|<br> Eva\u1E41 \u015Babdasya ni\u1E63patti\u1E25 \u015Babdavy\u0101pta\u1E41 car\u0101caram||</p></blockquote><p>ity\u0101din\u0101 granthena parabhairav\u012Byapar\u0101v\u0101k\u015Bakty\u0101tmakam\u0101t\u1E5Bk\u0101ta eva jye\u1E63\u1E6Dh\u0101raudryamb\u0101khya\u015Baktiprasarasambhedavaicitrye\u1E47a sarvavar\u1E47odayasyoktatv\u0101dvar\u1E47asa\u1E45gha\u1E6D\u1E6Dan\u0101\u015Bar\u012Br\u0101\u1E47\u0101\u1E41 mantr\u0101\u1E47\u0101\u1E41 saiva bhagavat\u012B vy\u0101khy\u0101tar\u016Bp\u0101 vidy\u0101\u015Bar\u012Brasatt\u0101 rahasyamiti pradar\u015Bitam| Praty\u0101gama\u1E41 ca m\u0101t\u1E5Bk\u0101m\u0101lin\u012Bprast\u0101rap\u016Brvaka\u1E41 mantroddh\u0101rakathanasy\u0101yamev\u0101\u015Baya\u1E25| Rahasy\u0101gamas\u0101rasa\u1E45grahar\u016Bpatv\u0101cchivas\u016Btr\u0101\u1E47\u0101m\u0101gamasa\u1E41v\u0101de bharo&#39;sm\u0101bhi\u1E25 k\u1E5Bta iti n\u0101smabhyamas\u016Byitavyam| Evamapi sa\u1E41v\u0101dita \u0101game yadi rahasy\u0101rtho na buddhyate tasm\u0101tsadgurusapary\u0101 k\u0101ry\u0101| E\u1E63a ca s\u016Btr\u0101rtha\u1E25</p><blockquote><p>Tad\u0101kramya bala\u1E41 mantr\u0101\u1E25...|</p></blockquote><p>ityanena k\u0101rik\u0101dvayena spande dar\u015Bita\u1E25||3||</p></div><hr><p>[\u0421\u043B\u0435\u0434\u0443\u044E\u0449\u0438\u0439 \u0430\u0444\u043E\u0440\u0438\u0437\u043C] \u0438\u043C\u0435\u0435\u0442 \u0432 \u0432\u0438\u0434\u0443 <em>(lak\u1E63ayati)</em> \u0440\u0430\u043D\u0435\u0435 <em>(p\u016Brva)</em> \u0443\u043F\u043E\u043C\u0438\u043D\u0430\u0432\u0448\u0438\u0439\u0441\u044F <em>(upak\u1E63iptam)</em><sup>1</sup> \u043F\u043E\u0440\u043E\u0436\u0434\u0430\u044E\u0449\u0438\u0439 \u0438\u0441\u0442\u043E\u0447\u043D\u0438\u043A --\u0441\u0438\u043B\u044B, \u0438\u043B\u0438 \u043C\u043E\u0433\u0443\u0449\u0435\u0441\u0442\u0432\u0430-- <em>(v\u012Bryam)</em> \u043C\u0430\u043D\u0442\u0440\u044B <em>(mantrasya)</em>, \u043A\u043E\u0442\u043E\u0440\u044B\u0439 \u0434\u043E\u043B\u0436\u0435\u043D \u0431\u044B\u0442\u044C \u0434\u043E\u0441\u0442\u0438\u0433\u043D\u0443\u0442 <em>(s\u0101dhyasya)</em> \u0442\u0430\u043A\u0438\u043C <em>(\u012Bd\u1E5B\u015Ba)</em> \u043F\u043E\u0434\u0432\u0438\u0436\u043D\u0438\u043A\u043E\u043C <em>(s\u0101dhaka)</em>, [\u043A\u043E\u0442\u043E\u0440\u044B\u0439 \u043F\u0440\u0435\u0434\u043F\u0440\u0438\u043D\u0438\u043C\u0430\u0435\u0442 \u043D\u0430\u0441\u0442\u043E\u0439\u0447\u0438\u0432\u043E\u0435 \u0438 \u0441\u043F\u043E\u043D\u0442\u0430\u043D\u043D\u043E\u0435 \u0443\u0441\u0438\u043B\u0438\u0435]\u2014</p><blockquote><p><strong>[\u0421\u0438\u044F\u044E\u0449\u0435\u0435] \u0421\u0443\u0449\u0435\u0441\u0442\u0432\u043E\u0432\u0430\u043D\u0438\u0435, \u0438\u043B\u0438 \u0411\u044B\u0442\u0438\u0435 [\u0421\u043E\u0432\u0435\u0440\u0448\u0435\u043D\u043D\u043E\u0433\u043E \u042F-\u0421\u043E\u0437\u043D\u0430\u043D\u0438\u044F] <em>(satt\u0101)</em>, [\u0441\u043E\u0441\u0442\u043E\u044F\u0449\u0435\u0435 \u0438\u0437 \u043C\u043D\u043E\u0436\u0435\u0441\u0442\u0432\u0430 \u0441\u043B\u043E\u0432], \u0447\u044C\u0435\u0439 \u0441\u0443\u0449\u043D\u043E\u0441\u0442\u044C\u044E <em>(\u015Bar\u012Bra)</em> [\u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F] \u0437\u043D\u0430\u043D\u0438\u0435 [\u0432\u044B\u0441\u0448\u0435\u0439 \u043D\u0435\u0434\u0432\u043E\u0439\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0441\u0442\u0438] <em>(vidy\u0101)</em>, [\u0435\u0441\u0442\u044C] \u0441\u0435\u043A\u0440\u0435\u0442 <em>(rahasyam)</em> \u041C\u0430\u043D\u0442\u0440\u044B <em>(mantra)</em>||3||</strong></p></blockquote><p>[\u0410\u0442\u0440\u0438\u0431\u0443\u0442\u0438\u0432\u043D\u043E\u0435 \u0441\u043E\u0441\u0442\u0430\u0432\u043D\u043E\u0435 \u0441\u043B\u043E\u0432\u043E, \u0442\u0430\u043A\u0436\u0435 \u0438\u0437\u0432\u0435\u0441\u0442\u043D\u043E\u0435 \u043A\u0430\u043A Bahuvr\u012Bhi,] &quot;vidy\u0101\u015Bar\u012Bra&quot; <em>(vidy\u0101-\u015Bar\u012Bra\u1E25)</em> <sup>2</sup></p><p>[\u043E\u0437\u043D\u0430\u0447\u0430\u0435\u0442] \u0442\u043E\u0433\u043E <em>(sa\u1E25)</em>, \u0447\u044C\u0435\u0439 <em>(yasya)</em> \u0441\u0443\u0449\u043D\u043E\u0441\u0442\u044C\u044E <em>(\u015Bar\u012Bram)</em>, [\u0438\u043B\u0438] \u043F\u0440\u0438\u0440\u043E\u0434\u043E\u0439 <em>(sva-r\u016Bpam)</em> \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u0437\u043D\u0430\u043D\u0438\u0435 <em>(vidy\u0101)</em>, \u0430 \u0438\u043C\u0435\u043D\u043D\u043E, \u0437\u043D\u0430\u043D\u0438\u0435 <em>(prath\u0101)</em> \u0432\u044B\u0441\u0448\u0435\u0439 <em>(para)</em> \u043D\u0435\u0434\u0432\u043E\u0439\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0441\u0442\u0438 <em>(advaya)</em>. [\u042D\u0442\u043E vidy\u0101\u015Bar\u012Bra] \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u0432\u043E\u0441\u0445\u0438\u0442\u0438\u0442\u0435\u043B\u044C\u043D\u044B\u043C <em>(bhagav\u0101n)</em> \u043C\u043D\u043E\u0436\u0435\u0441\u0442\u0432\u043E\u043C <em>(r\u0101\u015Bi\u1E25)</em> \u0441\u043B\u043E\u0432 <em>(\u015Babda)</em>. \u0422\u043E\u0442, \u043A\u0442\u043E <em>(y\u0101)</em> [\u0435\u0441\u0442\u044C \u0441\u0432\u0435\u0442\u044F\u0449\u0435\u0435\u0441\u044F] \u0421\u0443\u0449\u0435\u0441\u0442\u0432\u043E\u0432\u0430\u043D\u0438\u0435, \u0438\u043B\u0438 \u0411\u044B\u0442\u0438\u0435 <em>(satt\u0101)</em> \u044D\u0442\u043E\u0433\u043E [vidy\u0101\u015Bar\u012Bra, \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u043D\u0438\u0447\u0435\u043C \u0438\u043D\u044B\u043C \u043A\u0430\u043A] Sphuratt\u0101 --\u0442.\u0435. &quot;\u043F\u0443\u043B\u044C\u0441\u0438\u0440\u0443\u044E\u0449\u0435\u0439 \u0432\u0441\u043F\u044B\u0448\u043A\u043E\u0439&quot;, \u044D\u043F\u0438\u0442\u0435\u0442 \u015Aakti-- <em>(sphuratt\u0101)</em>, \u0447\u044C\u0435\u0439 \u043F\u0440\u0438\u0440\u043E\u0434\u043E\u0439 <em>(\u0101tm\u0101)</em> [\u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F] \u0441\u043E\u0432\u0435\u0440\u0448\u0435\u043D\u043D\u043E\u0435 <em>(p\u016Br\u1E47a)</em> \u042F-\u0421\u043E\u0437\u043D\u0430\u043D\u0438\u0435 <em>(aham-vimar\u015Bana)</em>, \u043A\u043E\u0442\u043E\u0440\u043E\u0435 \u043D\u0435 \u043E\u0442\u043B\u0438\u0447\u0430\u0435\u0442\u0441\u044F --\u0442.\u0435. \u043D\u0430\u043F\u043E\u043B\u043D\u0435\u043D\u043E \u0435\u0434\u0438\u043D\u0441\u0442\u0432\u043E\u043C-- <em>(abheda-maya)</em> \u043E\u0442 \u0432\u0441\u0435\u0439 <em>(a\u015Be\u1E63a)</em> \u0432\u0441\u0435\u043B\u0435\u043D\u043D\u043E\u0439 <em>(vi\u015Bva)</em>. [\u0418] \u041E\u043D\u0430 --\u0442.\u0435. Sphuratt\u0101, \u0438\u043B\u0438 \u0431\u043E\u0436\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u0430\u044F \u015Aakti-- <em>(s\u0101)</em> [\u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F] \u0441\u0435\u043A\u0440\u0435\u0442\u043E\u043C <em>(rahasyam)</em>, [\u0438\u043B\u0438] \u0442\u0430\u0439\u043D\u043E\u0439 <em>(upani\u1E63ad)</em> \u043C\u0430\u043D\u0442\u0440 <em>(mantr\u0101\u1E47\u0101m)</em><sup>3</sup>&quot;|</p><p>\u042D\u0442\u043E <em>(yad)</em> \u0431\u044B\u043B\u043E [\u0442\u0430\u043A\u0436\u0435] \u0441\u043A\u0430\u0437\u0430\u043D\u043E <em>(uktam)</em> \u0432 \u0434\u043E\u0441\u0442\u043E\u0447\u0442\u0438\u043C\u043E\u043C Tantrasadbh\u0101va <em>(\u015Br\u012B-tantrasadbh\u0101ve)</em>:</p><blockquote><p>&quot;\u041E, \u0414\u043E\u0440\u043E\u0433\u0430\u044F <em>(priye)</em>!, \u0432\u0441\u0435 <em>(sarve)</em> \u043C\u0430\u043D\u0442\u0440\u044B <em>(mantr\u0101\u1E25)</em> \u0441\u043E\u0441\u0442\u043E\u044F\u0442 \u0438\u0437 <em>(\u0101tmak\u0101\u1E25)</em> \u0431\u0443\u043A\u0432 <em>(var\u1E47a)</em> \u0438 <em>(ca)</em> \u043E\u043D\u0438 --\u0442.\u0435. \u0431\u0443\u043A\u0432\u044B-- <em>(te)</em> [\u044F\u0432\u043B\u044F\u044E\u0442\u0441\u044F] \u0444\u043E\u0440\u043C\u0430\u043C\u0438 <em>(\u0101tmak\u0101\u1E25)</em> \u015Aakti <em>(\u015Bakti)</em>. \u015Aakti <em>(\u015Bakti\u1E25)</em> \u0434\u043E\u043B\u0436\u043D\u0430 \u0431\u044B\u0442\u044C \u0438\u0437\u0432\u0435\u0441\u0442\u043D\u0430 <em>(j\xF1ey\u0101)</em> \u043A\u0430\u043A M\u0101t\u1E5Bk\u0101 <em>(m\u0101t\u1E5Bk\u0101)</em><sup>4</sup> \u043D\u0435\u0441\u043E\u043C\u043D\u0435\u043D\u043D\u043E <em>(tu)</em>, \u0438 <em>(ca)</em> \u041E\u043D\u0430 --\u0442.\u0435. M\u0101t\u1E5Bk\u0101-- <em>(s\u0101)</em> \u0434\u043E\u043B\u0436\u043D\u0430 \u0431\u044B\u0442\u044C \u0438\u0437\u0432\u0435\u0441\u0442\u043D\u0430 <em>(j\xF1ey\u0101)</em> \u043A\u0430\u043A \u0438\u043C\u0435\u044E\u0449\u0430\u044F \u043F\u0440\u0438\u0440\u043E\u0434\u0443 <em>(\u0101tmik\u0101)</em> \u0428\u0438\u0432\u044B <em>(\u015Biva... iti)</em>&quot;||</p></blockquote><p>\u0412 \u044D\u0442\u043E\u043C \u0441\u0430\u043C\u043E\u043C [\u041F\u0438\u0441\u0430\u043D\u0438\u0438] --\u0442.\u0435. \u0432 Tantrasadbh\u0101va-- <em>(tatra eva ca)</em>, \u044D\u0442\u043E\u0442 <em>(ayam)</em> \u043F\u0440\u0435\u0434\u043C\u0435\u0442 <em>(artha\u1E25)</em>, \u0445\u043E\u0442\u044F \u0438 \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F <em>(api)</em> \u0447\u0440\u0435\u0437\u0432\u044B\u0447\u0430\u0439\u043D\u043E <em>(ati)</em> \u0442\u0430\u0439\u043D\u044B\u043C <em>(rahasya\u1E25)</em>, \u0431\u044B\u043B \u044F\u0441\u043D\u043E \u043E\u0442\u043E\u0431\u0440\u0430\u0436\u0435\u043D <em>(vitatya sphu\u1E6D\u012Bk\u1E5Bta\u1E25)</em>|</p><p>\u0421\u043E\u043E\u0442\u0432\u0435\u0442\u0441\u0442\u0432\u0435\u043D\u043D\u043E <em>(tath\u0101 ca)</em>, \u0441\u0434\u0435\u043B\u0430\u0432 <em>(k\u1E5Btv\u0101)</em> [\u0441\u043B\u0435\u0434\u0443\u044E\u0449\u0435\u0435] \u0432\u0441\u0442\u0443\u043F\u0438\u0442\u0435\u043B\u044C\u043D\u043E\u0435 <em>(p\u012B\u1E6Dhik\u0101)</em> \u0437\u0430\u044F\u0432\u043B\u0435\u043D\u0438\u0435 <em>(bandham)</em> [\u0432 \u043A\u0430\u0447\u0435\u0441\u0442\u0432\u0435 \u043F\u0440\u0435\u0434\u0443\u043F\u0440\u0435\u0436\u0434\u0435\u043D\u0438\u044F]:</p><blockquote><p>&quot;[\u041B\u044E\u0434\u0438] \u043D\u0435 <em>(na)</em> \u0437\u043D\u0430\u044E\u0442 <em>(j\u0101nanti)</em>, \u043D\u0438 \u0447\u0442\u043E \u0413\u0443\u0440\u0443 <em>(gurum)</em> \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u0411\u043E\u0433\u043E\u043C <em>(devam)</em> --\u0442\u0430\u043A\u0436\u0435 \u043A\u0430\u043A-- <em>(tath\u0101)</em> (\u0438 \u043D\u0438) \u043F\u0440\u0430\u043A\u0442\u0438\u043A <em>(samay\u0101n)</em>, \u0438\u0437\u043B\u043E\u0436\u0435\u043D\u043D\u044B\u0445 <em>(ukt\u0101n)</em> \u0432 \u041F\u0438\u0441\u0430\u043D\u0438\u044F\u0445 <em>(\u015B\u0101stra)</em>. \u041E\u043D\u0438 \u043F\u0440\u0438\u0432\u044F\u0437\u0430\u043D\u044B <em>(nirat\u0101\u1E25)</em> \u043A \u043B\u0438\u0446\u0435\u043C\u0435\u0440\u0438\u044E <em>(dambha)</em> [\u0438] \u043D\u0435\u0447\u0435\u0441\u0442\u043D\u043E\u0441\u0442\u0438 <em>(kau\u1E6Dilya)</em>, \u0441\u0442\u0440\u0435\u043C\u044F\u0442\u0441\u044F \u043A \u0443\u0434\u043E\u0432\u043E\u043B\u044C\u0441\u0442\u0432\u0438\u044F\u043C <em>(laulya-arth\u0101\u1E25)</em> [\u0438] \u043B\u0438\u0448\u0435\u043D\u044B <em>(ujjhit\u0101\u1E25)</em> kriy\u0101, \u0438\u043B\u0438 \u0434\u0443\u0445\u043E\u0432\u043D\u043E\u0439 \u0434\u0435\u044F\u0442\u0435\u043B\u044C\u043D\u043E\u0441\u0442\u0438 <em>(kriyay\u0101)</em>. \u041F\u043E \u044D\u0442\u043E\u0439 \u043F\u0440\u0438\u0447\u0438\u043D\u0435 <em>(asm\u0101t tu k\u0101ra\u1E47\u0101t)</em>, \u041E, \u0411\u043E\u0433\u0438\u043D\u044F <em>(devi)</em>!, \u043F\u043E\u0440\u043E\u0436\u0434\u0430\u044E\u0449\u0438\u0439 \u0438\u0441\u0442\u043E\u0447\u043D\u0438\u043A --\u0441\u0438\u043B\u044B, \u0438\u043B\u0438 \u043C\u043E\u0433\u0443\u0449\u0435\u0441\u0442\u0432\u0430-- [\u043C\u0430\u043D\u0442\u0440] <em>(v\u012Bryam)</em> \u0441\u043E\u043A\u0440\u044B\u0442 <em>(pragopitam)</em> \u041C\u043D\u043E\u0439 <em>(may\u0101)</em>. \u0411\u043B\u0430\u0433\u043E\u0434\u0430\u0440\u044F \u044D\u0442\u043E\u043C\u0443 \u0441\u043E\u043A\u0440\u044B\u0442\u0438\u044E <em>(tena guptena)</em>, \u043E\u043D\u0438 --\u0442.\u0435. \u043C\u0430\u043D\u0442\u0440\u044B-- <em>(te)</em> \u0431\u044B\u043B\u0438 \u0437\u0430\u0449\u0438\u0449\u0435\u043D\u044B \u0438 \u0441\u043E\u0445\u0440\u0430\u043D\u0435\u043D\u044B <em>(gupt\u0101\u1E25)</em>. \u0422\u043E, \u0447\u0442\u043E \u043E\u0441\u0442\u0430\u043B\u043E\u0441\u044C <em>(\u015Be\u1E63\u0101\u1E25)</em>, [\u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F] \u0442\u043E\u043B\u044C\u043A\u043E <em>(keval\u0101\u1E25)</em> \u0431\u0443\u043A\u0432\u0430\u043C\u0438 <em>(var\u1E47\u0101\u1E25)</em>, \u043D\u0435\u0441\u043E\u043C\u043D\u0435\u043D\u043D\u043E <em>(tu.. iti)</em>&quot;||</p></blockquote><p>[\u015Aiva] \u043D\u0430\u0447\u0438\u043D\u0430\u0435\u0442 [\u0421\u0432\u043E\u0435 \u043E\u0431\u044A\u044F\u0441\u043D\u0435\u043D\u0438\u0435 \u044D\u0442\u043E\u0439 \u0442\u0430\u0439\u043D\u044B] --\u0442.\u0435. \u043D\u0430\u0447\u0430\u0432-- <em>(upakramya)</em>:</p><blockquote><p>&quot;\u0422\u0430, \u043A\u0442\u043E <em>(y\u0101 s\u0101)</em> [\u0438\u0437\u0432\u0435\u0441\u0442\u043D\u0430 \u043A\u0430\u043A] M\u0101t\u1E5Bk\u0101 <em>(m\u0101t\u1E5Bk\u0101)</em> [\u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F] \u043F\u043E\u0438\u0441\u0442\u0438\u043D\u0435 <em>(tu)</em> \u0438\u0437\u043E\u0431\u0438\u043B\u0443\u044E\u0449\u0435\u0439 <em>(samanvit\u0101)</em> \u0432\u044B\u0441\u0448\u0438\u043C <em>(para)</em> \u0432\u0435\u043B\u0438\u043A\u043E\u043B\u0435\u043F\u0438\u0435\u043C <em>(tejas)</em>. \u042D\u0442\u0430 <em>(idam)</em> \u0432\u0441\u0435\u043B\u0435\u043D\u043D\u0430\u044F <em>(vi\u015Bvam)</em>, \u043E\u0442 Brahm\u0101 --\u0422\u0432\u043E\u0440\u0446\u0430-- <em>(sa-brahma)</em> \u0432\u043F\u043B\u043E\u0442\u044C \u0434\u043E \u043F\u043E\u0441\u043B\u0435\u0434\u043D\u0435\u0433\u043E <em>(antakam)</em> \u0438\u0437 \u043C\u0438\u0440\u043E\u0432 <em>(bhuvana)</em> \u043F\u0440\u043E\u043D\u0438\u0437\u0430\u043D\u0430 <em>(vy\u0101ptam)</em> \u0415\u044E <em>(tay\u0101)</em>. \u041E \u0411\u043E\u0433\u0438\u043D\u044F <em>(devi)</em>, \u043F\u043E\u0447\u0438\u0442\u0430\u0435\u043C\u0430\u044F <em>(arcite)</em> \u0431\u043E\u0433\u0430\u043C\u0438 <em>(sura)</em>!, [\u044D\u0442\u043E \u0432\u044B\u0441\u0448\u0435\u0435 \u0432\u0435\u043B\u0438\u043A\u043E\u043B\u0435\u043F\u0438\u0435] \u0432\u0441\u0435\u0433\u0434\u0430 <em>(sad\u0101)</em> \u043F\u0440\u0435\u0431\u044B\u0432\u0430\u0435\u0442 <em>(stham)</em> \u0442\u0430\u043C --\u0432 M\u0101t\u1E5Bk\u0101-- <em>(tatra)</em> \u0438 <em>(ca... ca)</em> \u0438 \u043D\u0430\u043F\u043E\u043B\u043D\u0435\u043D\u043E [\u0415\u044E] <em>(vy\u0101pitam)</em>. \u041E \u0414\u043E\u0440\u043E\u0433\u0430\u044F <em>(priye)</em>!, \u043F\u043E\u0442\u043E\u043C\u0443 <em>(tath\u0101)</em> \u042F <em>(aham)</em> \u0441\u043A\u0430\u0436\u0443 <em>(kathayi\u1E63y\u0101mi)</em> \u0442\u0435\u0431\u0435 <em>(tava)</em> \u044F\u0441\u043D\u043E <em>(sphu\u1E6Dam)</em>, \u0434\u043B\u044F <em>(artham)</em> [\u0442\u0432\u043E\u0435\u0433\u043E] \u043F\u043E\u043B\u043D\u043E\u0433\u043E \u043F\u0440\u043E\u044F\u0441\u043D\u0435\u043D\u0438\u044F <em>(nir\u1E47aya)</em>, \u043A\u0430\u043A <em>(yath\u0101)</em> \u0422\u043E, \u0447\u0442\u043E \u043D\u0430\u0445\u043E\u0434\u0438\u0442\u0441\u044F <em>(stha\u1E25)</em> \u0432 \u0431\u0443\u043A\u0432\u0435 <em>(var\u1E47a)</em> &quot;a&quot; <em>(a)</em> --\u0442.\u0435. \u015Aiva, \u0412\u044B\u0441\u0448\u0438\u0439 \u0413\u043E\u0441\u043F\u043E\u0434\u044C-- \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F <em>(sthita\u1E25)</em> \u0432\u0435\u0437\u0434\u0435\u0441\u0443\u0449\u0438\u043C <em>(sarvagata\u1E25)</em> \u0432\u043E [\u0432\u0441\u0435\u0445] \u0431\u0443\u043A\u0432\u0430\u0445 [\u0430\u043B\u0444\u0430\u0432\u0438\u0442\u0430] <em>(var\u1E47a\u1E25)</em>&quot;|</p></blockquote><p>[\u015Aiva \u043F\u0440\u043E\u0434\u043E\u043B\u0436\u0430\u0435\u0442 \u0433\u043E\u0432\u043E\u0440\u0438\u0442\u044C]:</p><blockquote><p>&quot;\u042D\u0442\u0430 <em>(s\u0101)</em> \u015Aakti, \u0438\u043B\u0438 [\u0431\u043E\u0436\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u0430\u044F] \u0421\u0438\u043B\u0430 <em>(\u015Bakti\u1E25)</em> \u043E\u043F\u0438\u0441\u044B\u0432\u0430\u0435\u0442\u0441\u044F \u043A\u0430\u043A <em>(k\u012Brtit\u0101)</em> &#39;\u0432\u0435\u043B\u0438\u0447\u0430\u0439\u0448\u0430\u044F <em>(par\u0101)</em>, \u0442\u043E\u043D\u043A\u0430\u044F <em>(s\u016Bk\u1E63m\u0101)</em> [\u0438] \u0441\u0432\u043E\u0431\u043E\u0434\u043D\u0430\u044F \u043E\u0442 \u0101c\u0101ra --\u0442.\u0435. \u043F\u0440\u0430\u0432\u0438\u043B \u043F\u043E\u0432\u0435\u0434\u0435\u043D\u0438\u044F, \u0434\u0443\u0445\u043E\u0432\u043D\u044B\u0445 \u043F\u0440\u0430\u043A\u0442\u0438\u043A \u0438 \u0442.\u043F.-- <em>(nir\u0101c\u0101r\u0101 iti)</em>&#39;. [\u041E\u043D\u0430,] \u0437\u0430\u043A\u043B\u044E\u0447\u0438\u0432 <em>(ve\u1E63\u1E6Dayitv\u0101)</em> \u0432\u043D\u0443\u0442\u0440\u0438 \u0441\u0435\u0431\u044F <em>(antar)</em> \u0441\u0435\u0440\u0434\u0435\u0447\u043D\u043E\u0435 <em>(h\u1E5Bd)</em> \u0411\u0438\u043D\u0434\u0443 <em>(bindum)</em>, \u043F\u0440\u043E\u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u0432 \u0444\u043E\u0440\u043C\u0435 <em>(\u0101k\u1E5Bti\u1E25)</em> \u043A\u0440\u0435\u043F\u043A\u043E \u0441\u043F\u044F\u0449\u0435\u0439 <em>(su\u1E63upta)</em> \u0437\u043C\u0435\u0438 <em>(bhujaga)</em><sup>5</sup>. \u041E, \u0447\u0440\u0435\u0437\u0432\u044B\u0447\u0430\u0439\u043D\u043E \u0443\u0434\u0430\u0447\u043B\u0438\u0432\u0430\u044F <em>(mah\u0101bh\u0101ge)</em> Um\u0101 <em>(ume)</em>!, \u0432\u043E \u0432\u0440\u0435\u043C\u044F \u0441\u043D\u0430 <em>(supt\u0101)</em> \u0442\u0430\u043C <em>(tatra)</em> \u041E\u043D\u0430 \u043D\u0435 \u0434\u0443\u043C\u0430\u0435\u0442 <em>(manyate)</em> \u043D\u0438 \u043E \u0447\u0435\u043C <em>(na ki\xF1cid)</em>. \u0417\u0430\u0431\u0440\u043E\u0441\u0438\u0432 <em>(k\u1E63iptv\u0101)</em> \u0432\u043D\u0443\u0442\u0440\u044C [\u0441\u0432\u043E\u0435\u0433\u043E \u0441\u043E\u0431\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0433\u043E] \u043B\u043E\u043D\u0430 <em>(udare tu)</em> \u0447\u0435\u0442\u044B\u0440\u043D\u0430\u0434\u0446\u0430\u0442\u044C <em>(caturda\u015Ba)</em> \u043C\u0438\u0440\u043E\u0432 <em>(bhuvan\u0101ni)</em> \u043D\u0430\u0440\u044F\u0434\u0443 \u0441 \u043B\u0443\u043D\u043E\u0439 <em>(candra)</em>, \u043E\u0433\u043D\u0435\u043C <em>(agni)</em>, \u0441\u043E\u043B\u043D\u0446\u0435\u043C <em>(ravi)</em> [\u0438] \u0437\u0432\u0435\u0437\u0434\u0430\u043C\u0438 --nak\u1E63atra-- <em>(nak\u1E63atrai\u1E25)</em>, \u044D\u0442\u0430 <em>(y\u0101... s\u0101)</em> \u0431\u043E\u0433\u0438\u043D\u044F <em>(dev\u012B)</em> \u043A\u0430\u0436\u0435\u0442\u0441\u044F <em>(gat\u0101)</em> \u043A\u0430\u043A \u0431\u044B <em>(iva)</em> \u0431\u0435\u0441\u0441\u043E\u0437\u043D\u0430\u0442\u0435\u043B\u044C\u043D\u043E\u0439 <em>(m\u016B\u1E0Dh\u0101)</em> \u0438\u0437-\u0437\u0430 \u044F\u0434\u0430 <em>(vi\u1E63a)</em> --\u0442.\u0435. \u043F\u043E\u0441\u043B\u0435 \u043F\u0440\u043E\u044F\u0432\u043B\u0435\u043D\u0438\u044F \u0432\u0441\u0435\u0439 \u0432\u0441\u0435\u043B\u0435\u043D\u043D\u043E\u0439 \u041E\u043D\u0430 \u043E\u0441\u0442\u0430\u0435\u0442\u0441\u044F \u0442\u0430\u043C \u043A\u0440\u0435\u043F\u043A\u043E \u0441\u043F\u044F\u0449\u0435\u0439, \u043A\u0430\u043A \u0431\u0443\u0434\u0442\u043E \u0431\u0435\u0437 \u0441\u043E\u0437\u043D\u0430\u043D\u0438\u044F--.</p></blockquote><blockquote><p>[\u0417\u0430\u0442\u0435\u043C,] \u043E \u0421\u043F\u0440\u0430\u0432\u0435\u0434\u043B\u0438\u0432\u0430\u044F <em>(vara-var\u1E47ini)</em>!, \u041E\u043D\u0430 <em>(s\u0101)</em> \u043F\u0440\u043E\u0431\u0443\u0436\u0434\u0430\u0435\u0442\u0441\u044F <em>(prabuddh\u0101)</em> \u0441 \u0432\u0438\u0431\u0440\u0430\u0446\u0438\u0435\u0439 <em>(nin\u0101dena)</em> \u0432\u044B\u0441\u0448\u0435\u0433\u043E <em>(pare\u1E47a)</em> \u0437\u043D\u0430\u043D\u0438\u044F <em>(j\xF1\u0101na-r\u016Bpi\u1E47\u0101)</em>, \u0431\u0443\u0434\u0443\u0447\u0438 \u0432\u0437\u0431\u0438\u0442\u043E\u0439 <em>(mathit\u0101 ca)</em> \u043F\u043E\u0441\u0440\u0435\u0434\u0441\u0442\u0432\u043E\u043C Vindu --Bindu, \u0438\u043B\u0438 Vindu \u2014 \u044D\u0442\u043E \u043E\u0434\u043D\u043E \u0438 \u0442\u043E \u0436\u0435, \u043F\u043E\u0441\u043A\u043E\u043B\u044C\u043A\u0443 &quot;b&quot; \u0438 &quot;v&quot; \u043C\u043E\u0436\u043D\u043E \u043E\u0431\u044B\u0447\u043D\u043E \u0437\u0430\u043C\u0435\u043D\u0438\u0442\u044C-- <em>(vindun\u0101)</em>, \u043A\u043E\u0442\u043E\u0440\u044B\u0439 \u0440\u0430\u0441\u043F\u043E\u043B\u043E\u0436\u0435\u043D <em>(sthena)</em> \u0432 [\u0415\u0435] \u043B\u043E\u043D\u0435 <em>(udara)</em>. \u0412\u0437\u0431\u0430\u043B\u0442\u044B\u0432\u0430\u043D\u0438\u0435 <em>(mathanam)</em> [\u043F\u0440\u043E\u0434\u043E\u043B\u0436\u0430\u0435\u0442\u0441\u044F], \u0432 \u0434\u0435\u0439\u0441\u0442\u0432\u0438\u0442\u0435\u043B\u044C\u043D\u043E\u0441\u0442\u0438, \u043D\u0435\u043A\u043E\u0442\u043E\u0440\u043E\u0435 \u0432\u0440\u0435\u043C\u044F <em>(t\u0101vat vai)</em> \u0441 \u0432\u0440\u0430\u0449\u0435\u043D\u0438\u0435\u043C <em>(bhrama)</em> \u0441\u0438\u043B\u044B <em>(vegena)</em> \u0432 \u0442\u0435\u043B\u0435 <em>(vigrahe)</em> \u015Aakti <em>(\u015Bakti)</em> [\u0434\u043E \u0442\u043E\u0433\u043E \u043C\u043E\u043C\u0435\u043D\u0442\u0430, \u043A\u043E\u0433\u0434\u0430] \u0441 \u043F\u0440\u043E\u043D\u0438\u043A\u043D\u043E\u0432\u0435\u043D\u0438\u0435\u043C [\u0438\u0437 Bindu] <em>(bhed\u0101t tu)</em>, [\u0434\u043E\u043F\u043E\u043B\u043D\u0438\u0442\u0435\u043B\u044C\u043D\u044B\u0435] Bindu-s --\u043A\u0430\u043F\u043B\u0438 \u0441\u0432\u0435\u0442\u0430-- <em>(vindava\u1E25)</em> \u043F\u0440\u043E\u044F\u0432\u044F\u0442\u0441\u044F <em>(utpann\u0101\u1E25)</em> \u0432\u043F\u0435\u0440\u0432\u044B\u0435 --\u0442.\u0435. \u043F\u0435\u0440\u0432\u044B\u0435-- <em>(prathama)</em>. \u041E\u043D\u0438 -- Bindu-s, \u0438\u043B\u0438 \u043A\u0430\u043F\u043B\u0438 \u0441\u0432\u0435\u0442\u0430-- <em>(te)</em> \u043E\u0447\u0435\u043D\u044C \u0431\u043B\u0435\u0441\u0442\u044F\u0449\u0438\u0435 \u0438 \u043D\u0430\u043F\u043E\u043B\u043D\u0435\u043D\u044B \u0432\u0435\u043B\u0438\u043A\u0438\u043C \u0441\u0438\u044F\u043D\u0438\u0435\u043C <em>(ativarcasa\u1E25)</em>.</p></blockquote><blockquote><p>\u041E\u0434\u043D\u0430\u043A\u043E <em>(tu)</em>, \u043A\u043E\u0433\u0434\u0430 <em>(yad\u0101)</em> \u0442\u043E\u043D\u043A\u0430\u044F <em>(s\u016Bk\u1E63m\u0101 tu)</em> Kal\u0101 Ku\u1E47\u1E0Dal\u012B --\u0442.\u0435. \u043A\u043E\u043B\u044C\u0446\u0435\u043E\u0431\u0440\u0430\u0437\u043D\u0430\u044F Kal\u0101, \u0438\u043B\u0438 \u015Aakti-- *(kal\u0101... ku\u1E47\u1E0Dal\u012B)*\u043F\u0440\u043E\u0431\u0443\u0436\u0434\u0430\u0435\u0442\u0441\u044F <em>(utthit\u0101)</em> \u0442\u0430\u043A\u0438\u043C \u043E\u0431\u0440\u0430\u0437\u043E\u043C --\u0442.\u0435. \u043F\u043E\u0441\u0440\u0435\u0434\u0441\u0442\u0432\u043E\u043C \u0432\u0438\u0431\u0440\u0430\u0446\u0438\u0438 \u0432\u044B\u0441\u0448\u0435\u0433\u043E \u0437\u043D\u0430\u043D\u0438\u044F-- <em>(tena)</em>, [\u0442\u043E\u0433\u0434\u0430] \u043E \u0414\u043E\u0440\u043E\u0433\u0430\u044F <em>(priye)</em>!, \u043C\u043E\u0433\u0443\u0447\u0438\u0439 <em>(prabhu\u1E25)</em> \u0447\u0435\u0442\u044B\u0440\u0435\u0445-\u0444\u0430\u0437\u043D\u044B\u0439 <em>(catu\u1E63kala-maya\u1E25)</em> Vindu <em>(vindu\u1E25)</em>, \u043F\u0440\u0435\u0431\u044B\u0432\u0430\u044E\u0449\u0438\u0439 <em>(ga\u1E25)</em> \u0432 \u043B\u043E\u043D\u0435 <em>(udara)</em> \u015Aakti <em>(\u015Bakte\u1E25)</em>, \u0441\u0442\u0430\u043D\u043E\u0432\u0438\u0442\u0441\u044F \u043F\u0440\u044F\u043C\u044B\u043C <em>(\u1E5Bjutvam j\u0101yate)</em> \u043F\u043E\u0441\u0440\u0435\u0434\u0441\u0442\u0432\u043E\u043C \u0435\u0434\u0438\u043D\u0435\u043D\u0438\u044F <em>(yogena)</em> \u0442\u043E\u0433\u043E, \u043A\u0442\u043E \u0432\u0437\u0431\u0438\u0432\u0430\u0435\u0442 --\u015Aiva \u0432 \u0444\u043E\u0440\u043C\u0435 Vindu-- <em>(manthana)</em> [\u0438] \u0442\u043E\u0433\u043E, \u0447\u0442\u043E \u0432\u0437\u0431\u0438\u0432\u0430\u0435\u0442\u0441\u044F --\u015Aakti-- <em>(mathya)</em>. \u0428\u0430\u043A\u0442\u0438, \u0438\u043B\u0438 \u0421\u0438\u043B\u0430 <em>(\u015Bakti\u1E25)</em>, \u043A\u043E\u0442\u043E\u0440\u0430\u044F \u043F\u0440\u043E\u0445\u043E\u0434\u0438\u0442 <em>(g\u0101)</em> \u0442\u043E\u0447\u043D\u043E \u043F\u043E\u0441\u0435\u0440\u0435\u0434\u0438\u043D\u0435 <em>(su-madhya)</em> \u043F\u0430\u0440\u044B <em>(dvaya)</em> Vindu-s --\u0442.\u0435. \u043C\u0435\u0436\u0434\u0443 \u015Aiva \u0438 \u015Aakti-- <em>(vindu)</em> \u043D\u0430\u0437\u044B\u0432\u0430\u0435\u0442\u0441\u044F <em>(sm\u1E5Bt\u0101... tu)</em> Jye\u1E63\u1E6Dh\u0101 <em>(jye\u1E63\u1E6Dh\u0101)</em>.</p></blockquote><blockquote><p>[\u041A\u0440\u043E\u043C\u0435 \u0442\u043E\u0433\u043E,] \u041E\u043D\u0430, \u0431\u0443\u0434\u0443\u0447\u0438 \u0432\u043E\u0437\u0431\u0443\u0436\u0434\u0435\u043D\u043E\u0439 <em>(k\u1E63obham \u0101y\u0101t\u0101)</em> \u043F\u043E\u0441\u0440\u0435\u0434\u0441\u0442\u0432\u043E\u043C Vindu <em>(vindun\u0101)</em>, (\u043A\u0430\u043A) \u043E\u0447\u0435\u043D\u044C \u043F\u0440\u044F\u043C\u0430\u044F \u043B\u0438\u043D\u0438\u044F <em>(rekh\u0101 eva)</em>, [\u0438\u0437\u0432\u0435\u0441\u0442\u043D\u0430 \u043A\u0430\u043A] Am\u1E5Btaku\u1E47\u1E0Dal\u012B <em>(am\u1E5Bta-ku\u1E47\u1E0Dal\u012B)</em>. [\u0412 \u0441\u0432\u043E\u044E \u043E\u0447\u0435\u0440\u0435\u0434\u044C,] \u041E\u043D\u0430 <em>(s\u0101)</em> [\u0442\u0430\u043A\u0436\u0435] \u0438\u0437\u0432\u0435\u0441\u0442\u043D\u0430 <em>(j\xF1ey\u0101)</em> \u043F\u043E\u0434 \u0438\u043C\u0435\u043D\u0435\u043C <em>(n\u0101ma)</em> Rekhi\u1E47\u012B --\u0442.\u0435. \u0442\u043E\u0439, \u0447\u044C\u0435\u0439 \u0444\u043E\u0440\u043C\u043E\u0439 \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u043F\u0440\u044F\u043C\u0430\u044F \u043B\u0438\u043D\u0438\u044F-- <em>(rekhi\u1E47\u012B)</em>, \u044F\u0432\u043B\u044F\u044E\u0449\u0435\u0439\u0441\u044F <em>(gau)</em> \u043E\u0431\u043E\u0438\u043C\u0438 <em>(ubhau)</em> Vindu-s --\u043F\u0435\u0440\u0432\u044B\u0439 \u0438\u0437 \u015Aiva \u043D\u0430\u0432\u0435\u0440\u0445\u0443, \u0442\u043E\u0433\u0434\u0430 \u043A\u0430\u043A \u0438\u0437 \u015Aakti \u2014 \u0432\u043D\u0438\u0437\u0443-- <em>(vind\u016B)</em>, \u0432 \u043A\u043E\u043D\u0446\u0435 <em>(anta)</em> \u043A\u043E\u0442\u043E\u0440\u043E\u0439 --\u0442.\u0435. Rekhi\u1E47\u012B-- <em>(yad)</em>. \u041E\u043D\u0430 <em>(s\u0101)</em> \u0437\u043E\u0432\u0435\u0442\u0441\u044F <em>(sam\u0101khy\u0101t\u0101)</em> Tripath\u0101 --\u0442.\u0435. \u0442\u0430, \u043A\u043E\u0442\u043E\u0440\u0430\u044F \u0438\u043C\u0435\u0435\u0442 \u0442\u0440\u0438 \u043D\u0430\u043F\u0440\u0430\u0432\u043B\u0435\u043D\u0438\u044F, \u0438\u043B\u0438 \u043F\u0443\u0442\u0438-- <em>(\u015Bakti)</em> [\u0438] \u0438\u0437\u0432\u0435\u0441\u0442\u043D\u0430 <em>(g\u012Byate)</em> \u043F\u043E\u0434 \u0438\u043C\u0435\u043D\u0435\u043C <em>(n\u0101mn\u0101 tu)</em> Raudr\u012B <em>(raudr\u012B)</em> [\u0442\u0430\u043A\u0436\u0435]. \u041E\u043D\u0430 <em>(s\u0101)</em> \u043D\u0430\u0437\u0432\u0430\u043D\u0430 \u043A\u0430\u043A <em>(samuddi\u1E63\u1E6D\u0101)</em> Rodhin\u012B <em>(rodhin\u012B)</em>, \u043F\u043E\u0441\u043A\u043E\u043B\u044C\u043A\u0443 \u043E\u043D\u0430 \u043F\u0440\u0435\u043F\u044F\u0442\u0441\u0442\u0432\u0443\u0435\u0442 <em>(nirodhan\u0101t)</em> \u043D\u0430 \u043F\u0443\u0442\u0438 <em>(m\u0101rga)</em> \u043A \u041E\u043A\u043E\u043D\u0447\u0430\u0442\u0435\u043B\u044C\u043D\u043E\u043C\u0443 \u041E\u0441\u0432\u043E\u0431\u043E\u0436\u0434\u0435\u043D\u0438\u044E <em>(mok\u1E63a)</em>.</p></blockquote><blockquote><p>[\u0412 \u0437\u0430\u043A\u043B\u044E\u0447\u0435\u043D\u0438\u0435,] Ambik\u0101 <em>(ambik\u0101 ca)</em>, \u0447\u044C\u044F \u0444\u043E\u0440\u043C\u0430 <em>(\u0101k\u0101r\u0101)</em> \u0441\u043E\u0441\u0442\u043E\u0438\u0442 \u0438\u0437 \u0447\u0430\u0441\u0442\u0438 <em>(\u015Bakala)</em> \u043B\u0443\u043D\u044B <em>(\u015Ba\u015Ba-a\u1E45ka)</em>, [\u0432\u044B\u0433\u043B\u044F\u0434\u0438\u0442] \u043A\u0430\u043A \u043F\u043E\u043B\u0443\u043C\u0435\u0441\u044F\u0446 <em>(ardhacandrik\u0101)</em>. \u0422\u0430\u043A\u0438\u043C \u043E\u0431\u0440\u0430\u0437\u043E\u043C <em>(ittham)</em>, \u0412\u044B\u0441\u0448\u0430\u044F <em>(par\u0101)</em> \u015Aakti <em>(\u015Bakti\u1E25)</em>, [\u043A\u043E\u0442\u043E\u0440\u0430\u044F \u0435\u0441\u0442\u044C] \u0442\u043E\u043B\u044C\u043A\u043E <em>(eva)</em> \u043E\u0434\u043D\u0430 <em>(ek\u0101)</em>, \u043F\u0440\u043E\u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F <em>(s\u0101... praj\u0101yate)</em> \u043E\u043F\u0440\u0435\u0434\u0435\u043B\u0435\u043D\u043D\u043E <em>(tu)</em> \u0442\u0440\u0435\u043C\u044F \u043F\u0443\u0442\u044F\u043C\u0438 <em>(tridh\u0101)</em> --\u0442.\u0435. Jye\u1E63\u1E6Dh\u0101, Raudr\u012B and Ambik\u0101--. \u0427\u0435\u0440\u0435\u0437 \u044D\u0442\u0438 [\u0442\u0440\u0438 \u0444\u043E\u0440\u043C\u044B \u015Aakti] <em>(\u0101bhya\u1E25)</em>, \u043F\u043E\u0441\u0440\u0435\u0434\u0441\u0442\u0432\u043E\u043C \u0441\u043E\u0435\u0434\u0438\u043D\u0435\u043D\u0438\u0439 \u0438 \u0440\u0430\u0437\u044A\u0435\u0434\u0438\u043D\u0435\u043D\u0438\u0439 <em>(yukta-viyukt\u0101bhya\u1E25)</em>, \u0434\u0435\u0432\u044F\u0442\u044C <em>(nava)</em> \u0433\u0440\u0443\u043F\u043F [\u0431\u0443\u043A\u0432] <em>(vargaka\u1E25)</em> \u043F\u0440\u0438\u0432\u043E\u0434\u044F\u0442\u0441\u044F \u043A \u0441\u0443\u0449\u0435\u0441\u0442\u0432\u043E\u0432\u0430\u043D\u0438\u044E <em>(sa\xF1j\u0101ta\u1E25)</em>. \u0418 <em>(ca)</em> \u041E\u043D\u0430 <em>(s\u0101 tu)</em>, \u0445\u0430\u0440\u0430\u043A\u0442\u0435\u0440\u0438\u0437\u0443\u044E\u0449\u0430\u044F\u0441\u044F <em>(upalak\u1E63it\u0101)</em> \u0434\u0435\u0432\u044F\u0442\u044C\u044E <em>(nava)</em> \u0433\u0440\u0443\u043F\u043F\u0430\u043C\u0438 [\u0431\u0443\u043A\u0432] <em>(varga)</em>, \u043E\u043F\u0438\u0441\u044B\u0432\u0430\u0435\u0442\u0441\u044F <em>(sm\u1E5Bt\u0101)</em> \u0434\u0435\u0432\u044F\u0442\u044C\u044E \u043F\u0443\u0442\u044F\u043C\u0438 <em>(navadh\u0101)</em>.</p></blockquote><blockquote><p>\u041E \u0411\u043E\u0433\u0438\u043D\u044F <em>(devi)</em>!, \u041E\u043D\u0430 \u0441\u043E\u0434\u0435\u0440\u0436\u0438\u0442\u0441\u044F <em>(gat\u0101)</em> \u0432 \u043F\u044F\u0442\u0438 <em>(pa\xF1ca)</em> \u043C\u0430\u043D\u0442\u0440\u0430\u0445 <em>(mantra)</em>, [\u0438\u0437\u0432\u0435\u0441\u0442\u043D\u044B\u0445 \u043A\u0430\u043A] Sadyoj\u0101ta <em>(sadya)</em>, etc. <em>(\u0101di\u1E25)</em> \u043F\u043E\u0441\u043B\u0435\u0434\u043E\u0432\u0430\u0442\u0435\u043B\u044C\u043D\u043E <em>(anukram\u0101t)</em>. \u041F\u043E \u044D\u0442\u043E\u0439 \u043F\u0440\u0438\u0447\u0438\u043D\u0435 <em>(tena)</em>, \u043E \u0412\u043B\u0430\u0434\u044B\u0447\u0438\u0446\u0430 <em>(n\u0101yike)</em> \u0431\u043E\u0433\u043E\u0432 <em>(sura)</em>!, \u041E\u043D\u0430 \u043E\u043F\u0438\u0441\u0430\u043D\u0430 <em>(prokt\u0101)</em> [\u0438] \u0434\u043E\u043B\u0436\u043D\u0430 \u0431\u044B\u0442\u044C \u0438\u0437\u0432\u0435\u0441\u0442\u043D\u0430 <em>(j\xF1\u0101tavy\u0101)</em> \u043F\u044F\u0442\u044C\u044E \u0441\u043F\u043E\u0441\u043E\u0431\u0430\u043C\u0438 <em>(pa\xF1cavidh\u0101)</em>. \u041E \u0411\u043E\u0433\u0438\u043D\u044F <em>(devi)</em>!, \u043E \u041D\u0435\u0439 \u0433\u043E\u0432\u043E\u0440\u0438\u0442\u0441\u044F <em>(ud\u0101h\u1E5Bt\u0101)</em>, (\u0447\u0442\u043E \u041E\u043D\u0430) \u043F\u0440\u0435\u0431\u044B\u0432\u0430\u0435\u0442 <em>(sth\u0101)</em> \u0432 \u0434\u0432\u0435\u043D\u0430\u0434\u0446\u0430\u0442\u0438 <em>(dv\u0101da\u015Ba)</em>, [\u043F\u043E\u0441\u043A\u043E\u043B\u044C\u043A\u0443] \u041E\u043D\u0430 \u0441\u0443\u0449\u0435\u0441\u0442\u0432\u0443\u0435\u0442 <em>(g\u0101)</em> \u0432 \u0434\u0432\u0435\u043D\u0430\u0434\u0446\u0430\u0442\u0438 <em>(dv\u0101da\u015Ba)</em> \u0433\u043B\u0430\u0441\u043D\u044B\u0445 <em>(svara)</em>. \u041E\u043D\u0430 \u043F\u0440\u0435\u0431\u044B\u0432\u0430\u0435\u0442 <em>(sthit\u0101)</em> \u0432 \u0431\u0443\u043A\u0432\u0430\u0445 \u043E\u0442 <em>(k\u0101ra-\u0101di)</em> &#39;a&#39; <em>(a)</em> \u0434\u043E \u0431\u0443\u043A\u0432\u044B <em>(k\u0101ra-ant\u0101)</em> &#39;k\u1E63a&#39; <em>(k\u1E63a)</em> \u0432 \u0444\u043E\u0440\u043C\u0435 \u043F\u044F\u0442\u0438\u0434\u0435\u0441\u044F\u0442\u0438 <em>(pa\xF1c\u0101\u015Bat\u0101)</em> \u0440\u0430\u0437\u043D\u043E\u0432\u0438\u0434\u043D\u043E\u0441\u0442\u0435\u0439 <em>(bhid\u0101)</em>.</p></blockquote><blockquote><p>[\u0412\u043E \u0432\u0440\u0435\u043C\u044F] \u043F\u0440\u0435\u0431\u044B\u0432\u0430\u043D\u0438\u044F <em>(sth\u0101)</em> \u0432 \u0441\u0435\u0440\u0434\u0446\u0435 <em>(h\u1E5Bd)</em>, \u043E \u041D\u0435\u0439 \u0433\u043E\u0432\u043E\u0440\u044F\u0442 <em>(prokt\u0101)</em>, (\u0447\u0442\u043E \u041E\u043D\u0430) \u0441\u043E\u0441\u0442\u043E\u0438\u0442 \u0438\u0437 \u043E\u0434\u043D\u043E\u0433\u043E \u0430\u0442\u043E\u043C\u0430 <em>(eka-\u0101\u1E47av\u0101)</em>; [\u0430 \u043A\u043E\u0433\u0434\u0430] \u0432 \u0433\u043E\u0440\u043B\u0435 <em>(ka\u1E47\u1E6Dhe)</em>, \u043E \u041D\u0435\u0439 \u0433\u043E\u0432\u043E\u0440\u044F\u0442 <em>(prokt\u0101)</em> \u043A\u0430\u043A \u043E \u0441\u043E\u0441\u0442\u0430\u0432\u043B\u0435\u043D\u043D\u043E\u0439 \u0438\u0437 \u0434\u0432\u0443\u0445 [\u0430\u0442\u043E\u043C\u043E\u0432] <em>(dvit\u012Byak\u0101)</em>. \u041E\u0434\u043D\u0430\u043A\u043E <em>(tu)</em>, \u0432\u0441\u0435\u0433\u0434\u0430 <em>(sad\u0101)</em> \u0440\u0430\u0441\u043F\u043E\u043B\u043E\u0436\u0435\u043D\u043D\u0430\u044F <em>(sthit\u0101)</em> \u0432 \u043A\u043E\u0440\u043D\u0435 <em>(m\u016Ble)</em> \u044F\u0437\u044B\u043A\u0430 <em>(jihv\u0101)</em>, \u041E\u043D\u0430 \u0434\u043E\u043B\u0436\u043D\u0430 \u0431\u044B\u0442\u044C \u0438\u0437\u0432\u0435\u0441\u0442\u043D\u0430 \u043A\u0430\u043A <em>(j\xF1\u0101tavy\u0101)</em> \u0441\u0444\u043E\u0440\u043C\u0438\u0440\u043E\u0432\u0430\u043D\u043D\u0430\u044F \u0438\u0437 \u0442\u0440\u0435\u0445 \u0430\u0442\u043E\u043C\u043E\u0432 <em>(tris-\u0101\u1E47av\u0101)</em>. \u041D\u0430 \u043A\u043E\u043D\u0447\u0438\u043A\u0435 <em>(agre)</em> \u044F\u0437\u044B\u043A\u0430 <em>(jihv\u0101)</em> \u043F\u043E\u044F\u0432\u043B\u044F\u044E\u0442\u0441\u044F <em>(ni\u1E63patti\u1E25)</em> \u0431\u0443\u043A\u0432\u044B <em>(var\u1E47a)</em>, [\u0438] \u043D\u0435\u0442 \u043D\u0438\u043A\u0430\u043A\u0438\u0445 <em>(na)</em> \u0441\u043E\u043C\u043D\u0435\u043D\u0438\u0439 <em>(sa\u1E41\u015Baya\u1E25)</em> \u043E\u0442\u043D\u043E\u0441\u0438\u0442\u0435\u043B\u044C\u043D\u043E \u044D\u0442\u043E\u0433\u043E <em>(atra)</em>. \u0421\u043E\u0437\u0434\u0430\u043D\u0438\u0435 <em>(ni\u1E63patti\u1E25)</em> \u0441\u043B\u043E\u0432 <em>(\u015Babdasya)</em> [\u0441\u043B\u0443\u0447\u0430\u0435\u0442\u0441\u044F] \u0442\u0430\u043A\u0438\u043C \u0436\u0435 \u043E\u0431\u0440\u0430\u0437\u043E\u043C <em>(evam)</em>. [\u041C\u0438\u0440, \u043A\u043E\u0442\u043E\u0440\u044B\u0439 \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F] \u0441\u043E\u0432\u043E\u043A\u0443\u043F\u043D\u043E\u0441\u0442\u044C\u044E \u0432\u0441\u0435\u0445 \u0441\u043E\u0442\u0432\u043E\u0440\u0435\u043D\u043D\u044B\u0445 \u0432\u0435\u0449\u0435\u0439, \u043A\u0430\u043A \u043E\u0434\u0443\u0448\u0435\u0432\u043B\u0435\u043D\u043D\u044B\u0445, \u0442\u0430\u043A \u0438 \u043D\u0435\u043E\u0434\u0443\u0448\u0435\u0432\u043B\u0435\u043D\u043D\u044B\u0445 *(cara-acaram)*\u043D\u0430\u043F\u043E\u043B\u043D\u0435\u043D <em>(vy\u0101ptam)</em> \u0441\u043B\u043E\u0432\u0430\u043C\u0438 <em>(\u015Babda)</em>&quot;||</p></blockquote><p>\u0438 \u0442.\u0434., \u0441\u043E\u0433\u043B\u0430\u0441\u043D\u043E \u044D\u0442\u0438\u043C \u0438 \u0434\u0440\u0443\u0433\u0438\u043C \u0443\u0442\u0432\u0435\u0440\u0436\u0434\u0435\u043D\u0438\u044F\u043C <em>(iti-\u0101din\u0101)</em>, \u0432\u044B\u0440\u0430\u0436\u0435\u043D\u043D\u044B\u043C \u0432 \u043A\u043D\u0438\u0433\u0435 --\u0442.\u0435. Tantrasadbh\u0101va-- <em>(granthena)</em>, M\u0101t\u1E5Bk\u0101 <em>(m\u0101t\u1E5Bk\u0101)</em> \u0441\u043E\u0441\u0442\u043E\u0438\u0442 \u0438\u0437 <em>(\u0101tmaka)</em> Par\u0101v\u0101k --\u0412\u044B\u0441\u0448\u0435\u0439 \u0420\u0435\u0447\u0438, \u0438\u043B\u0438 Par\u0101\u015Bakti, \u0438\u0437 \u043A\u043E\u0442\u043E\u0440\u043E\u0439 \u0432\u043E\u0437\u043D\u0438\u043A\u0430\u044E\u0442 \u0432\u0441\u0435 \u0431\u0443\u043A\u0432\u044B-- <em>(par\u0101v\u0101k)</em>, \u043A\u043E\u0442\u043E\u0440\u0430\u044F \u0435\u0441\u0442\u044C \u015Aakti, \u0438\u043B\u0438 \u0421\u0438\u043B\u0430 <em>(\u015Bakti)</em> \u0412\u044B\u0441\u0448\u0435\u0433\u043E \u0411\u0445\u0430\u0439\u0440\u0430\u0432\u044B (Bhairava) --\u0412\u044B\u0441\u0448\u0435\u0433\u043E \u0413\u043E\u0441\u043F\u043E\u0434\u0430-- <em>(para-bhairav\u012Bya)</em>. \u0418\u043C\u0435\u043D\u043D\u043E \u043F\u043E \u044D\u0442\u043E\u0439 \u043F\u0440\u0438\u0447\u0438\u043D\u0435 <em>(atas eva)</em>, \u043A\u0430\u043A \u0431\u044B\u043B\u043E \u0441\u043A\u0430\u0437\u0430\u043D\u043E [\u0432 Tantrasadbh\u0101va] <em>(uktatv\u0101t)</em>, \u0447\u0442\u043E \u0432\u043E\u0437\u043D\u0438\u043A\u043D\u043E\u0432\u0435\u043D\u0438\u0435, \u0438\u043B\u0438 \u043F\u043E\u044F\u0432\u043B\u0435\u043D\u0438\u0435 <em>(udayasya)</em> \u0432\u0441\u0435\u0445 <em>(sarva)</em> \u0431\u0443\u043A\u0432 <em>(var\u1E47a)</em> \u0438\u0437-\u0437\u0430 \u043C\u043D\u043E\u0433\u043E\u043E\u0431\u0440\u0430\u0437\u0438\u044F <em>(vaicitrye\u1E47a)</em>, [\u0432\u044B\u0437\u0432\u0430\u043D\u043D\u043E\u0433\u043E] \u0441\u043E\u0435\u0434\u0438\u043D\u0435\u043D\u0438\u0435\u043C <em>(sambheda)</em> \u0440\u0430\u0441\u0448\u0438\u0440\u044F\u044E\u0449\u0438\u0445\u0441\u044F <em>(prasara)</em> \u015Bakti-s <em>(\u015Bakti)</em>, \u0447\u044C\u0438\u043C\u0438 \u0438\u043C\u0435\u043D\u0430\u043C\u0438 [\u044F\u0432\u043B\u044F\u044E\u0442\u0441\u044F] <em>(\u0101khya)</em> Jye\u1E63\u1E6Dh\u0101 <em>(jye\u1E63\u1E6Dh\u0101)</em>, Raudr\u012B <em>(raudr\u012B)</em> [\u0438] Amb\u0101, \u0438\u043B\u0438 Ambik\u0101 <em>(amb\u0101)</em>, [\u044D\u0442\u043E \u0435\u0441\u0442\u044C] \u0442\u043E\u043B\u044C\u043A\u043E <em>(eva)</em> \u0442\u0430 <em>(s\u0101)</em> \u0443\u0434\u0430\u0447\u043B\u0438\u0432\u0430\u044F <em>(bhagavat\u012B)</em> Vidy\u0101\u015Bar\u012Brasatt\u0101 \u2014[\u0441\u0432\u0435\u0442\u044F\u0449\u0435\u0435\u0441\u044F] \u0421\u0443\u0449\u0435\u0441\u0442\u0432\u043E\u0432\u0430\u043D\u0438\u0435, \u0438\u043B\u0438 \u0411\u044B\u0442\u0438\u0435 [\u0421\u043E\u0432\u0435\u0440\u0448\u0435\u043D\u043D\u043E\u0433\u043E \u042F-\u0421\u043E\u0437\u043D\u0430\u043D\u0438\u044F] <em>(satt\u0101)</em>, [\u043A\u043E\u0442\u043E\u0440\u0430\u044F \u0441\u043E\u0441\u0442\u043E\u0438\u0442 \u0438\u0437 \u043C\u043D\u043E\u0436\u0435\u0441\u0442\u0432\u0430 \u0441\u043B\u043E\u0432], \u0447\u044C\u0435\u0439 \u0441\u0443\u0449\u043D\u043E\u0441\u0442\u044C\u044E <em>(\u015Bar\u012Bra)</em> [\u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F] \u0437\u043D\u0430\u043D\u0438\u0435 [\u0432\u044B\u0441\u0448\u0435\u0439 \u043D\u0435\u0434\u0432\u043E\u0439\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0441\u0442\u0438] <em>(vidy\u0101)</em>\u2014, \u043A\u0430\u043A [\u0443\u0436\u0435] \u043E\u0431\u044A\u044F\u0441\u043D\u044F\u043B\u043E\u0441\u044C <em>(vy\u0101khy\u0101ta-r\u016Bp\u0101)</em>, \u0432 \u043A\u043E\u0442\u043E\u0440\u043E\u0439 \u0437\u0430\u043A\u043B\u044E\u0447\u0430\u0435\u0442\u0441\u044F \u0441\u0435\u043A\u0440\u0435\u0442 <em>(rahasyam)</em> \u043C\u0430\u043D\u0442\u0440 <em>(mantr\u0101\u1E47\u0101m)</em>, \u0432\u043E\u043F\u043B\u043E\u0449\u0435\u043D\u043D\u044B\u0445 <em>(\u015Bar\u012Br\u0101\u1E47\u0101m)</em> \u0432 \u0442\u0435\u0441\u043D\u043E\u043C \u0441\u043E\u0435\u0434\u0438\u043D\u0435\u043D\u0438\u0438 <em>(sa\u1E45gha\u1E6D\u1E6Dan\u0101)</em> \u0431\u0443\u043A\u0432 <em>(var\u1E47a)</em>. \u042D\u0442\u043E \u0442\u043E, \u0447\u0442\u043E \u0431\u044B\u043B\u043E \u043F\u043E\u043A\u0430\u0437\u0430\u043D\u043E \u0438 \u043F\u0440\u0435\u043F\u043E\u0434\u0430\u043D\u043E [\u0432 \u043F\u0440\u0438\u0432\u0435\u0434\u0435\u043D\u043D\u043E\u0439 \u0432\u044B\u0448\u0435 \u0446\u0438\u0442\u0430\u0442\u0435 \u0438\u0437 \u0437\u043D\u0430\u043C\u0435\u043D\u0438\u0442\u043E\u0433\u043E Tantrasadbh\u0101va] <em>(iti pradar\u015Bitam)</em>|</p><p>\u0412 \u043A\u0430\u0436\u0434\u043E\u0439 \u0100gama --\u043F\u0440\u043E\u044F\u0432\u043B\u0435\u043D\u043D\u043E\u043C \u041F\u0438\u0441\u0430\u043D\u0438\u0438-- <em>(prati-\u0101gamam ca)</em>, [\u0438\u043C\u0435\u0435\u0442\u0441\u044F] \u043D\u0430\u043C\u0435\u0440\u0435\u043D\u0438\u0435 <em>(\u0101\u015Baya\u1E25)</em> \u0438\u0437\u043B\u043E\u0436\u0435\u043D\u0438\u044F <em>(kathanasya)</em> (\u0443\u0447\u0435\u043D\u0438\u044F) \u043E \u043F\u043E\u044F\u0432\u043B\u0435\u043D\u0438\u0438 <em>(uddh\u0101ra)</em> \u043C\u0430\u043D\u0442\u0440 <em>(mantra)</em> \u0441\u043E\u0433\u043B\u0430\u0441\u043D\u043E <em>(p\u016Brvakam)</em> \u0440\u0430\u0441\u0448\u0438\u0440\u0435\u043D\u0438\u044E <em>(prast\u0101ra)</em> M\u0101t\u1E5Bk\u0101 <em>(m\u0101t\u1E5Bk\u0101)</em> [\u0438] M\u0101lin\u012B <em>(m\u0101lin\u012B)</em><sup>6</sup>|</p><p>\u041C\u044B \u0432\u044B\u043F\u043E\u043B\u043D\u0438\u043B\u0438 <em>(asm\u0101bhi\u1E25 k\u1E5Bta\u1E25)</em> \u0442\u044F\u0436\u0435\u043B\u0443\u044E \u0440\u0430\u0431\u043E\u0442\u0443 <em>(bhara\u1E25)</em>, [\u0447\u0442\u043E\u0431\u044B \u043F\u043E\u043A\u0430\u0437\u0430\u0442\u044C] \u0441\u043E\u043E\u0442\u0432\u0435\u0442\u0441\u0442\u0432\u0438\u0435 <em>(sa\u1E41v\u0101de)</em> \u043C\u0435\u0436\u0434\u0443 \u0100gama-s <em>(\u0101gama)</em> [\u0438] \u015Aivas\u016Btra-s <em>(\u015Bivas\u016Btr\u0101\u1E47\u0101m)</em>, \u043F\u043E\u0441\u043A\u043E\u043B\u044C\u043A\u0443 [\u043F\u043E\u0441\u043B\u0435\u0434\u043D\u0438\u0435] \u044F\u0432\u043B\u044F\u044E\u0442\u0441\u044F <em>(r\u016Bpatv\u0101t)</em> \u043A\u0440\u0430\u0442\u043A\u0438\u043C \u0438\u0437\u043B\u043E\u0436\u0435\u043D\u0438\u0435\u043C <em>(sa\u1E45graha)</em> \u0441\u0443\u0442\u0438 <em>(s\u0101ra)</em> \u0442\u0430\u0439\u043D\u044B\u0445 <em>(rahasya)</em> \u0100gama-s <em>(\u0101gama)</em>. \u041F\u043E\u044D\u0442\u043E\u043C\u0443 <em>(iti)</em>, [\u043B\u044E\u0434\u0438] \u043D\u0435 \u0434\u043E\u043B\u0436\u043D\u044B \u0431\u044B\u0442\u044C \u043D\u0435\u0434\u043E\u0432\u043E\u043B\u044C\u043D\u044B <em>(na... as\u016Byitavyam)</em> \u043D\u0430\u043C\u0438 <em>(asmabhyam)</em>|</p><p>\u0422\u0430\u043A\u0438\u043C \u043E\u0431\u0440\u0430\u0437\u043E\u043C <em>(evam)</em>, \u0434\u0430\u0436\u0435*(api)* \u0435\u0441\u043B\u0438 <em>(yadi)</em> \u043F\u043E\u0441\u043B\u0435 [\u0432\u0441\u0435\u0445] \u0441\u043E\u043E\u0442\u0432\u0435\u0442\u0441\u0442\u0432\u0438\u0439 \u0441 \u0100gama-s, [\u043D\u0430 \u043A\u043E\u0442\u043E\u0440\u044B\u0435 \u043C\u044B \u0443\u043A\u0430\u0437\u0430\u043B\u0438] <em>(sa\u1E41v\u0101dite \u0101game)</em>, \u0442\u0430\u0439\u043D\u044B\u0439 <em>(rahasya)</em> \u0441\u043C\u044B\u0441\u043B <em>(artha\u1E25)</em> \u043E\u0441\u0442\u0430\u0435\u0442\u0441\u044F [\u043F\u043E-\u043F\u0440\u0435\u0436\u043D\u0435\u043C\u0443] \u043D\u0435 \u043F\u043E\u043D\u044F\u0442\u044B\u043C <em>(na buddhyate)</em>, \u0442\u043E\u0433\u0434\u0430 <em>(tasm\u0101t)</em> \u0434\u043E\u043B\u0436\u043D\u043E \u0431\u044B\u0442\u044C \u0432\u044B\u043F\u043E\u043B\u043D\u0435\u043D\u043E <em>(k\u0101ry\u0101)</em> \u043F\u043E\u043A\u043B\u043E\u043D\u0435\u043D\u0438\u0435 <em>(sapary\u0101)</em> \u0438\u0441\u0442\u0438\u043D\u043D\u043E\u043C\u0443 <em>(sad)</em> Guru --\u0434\u0443\u0445\u043E\u0432\u043D\u043E\u043C\u0443 \u043D\u0430\u0441\u0442\u0430\u0432\u043D\u0438\u043A\u0443-- <em>(guru)</em>|</p><p>\u042D\u0442\u043E <em>(e\u1E63a\u1E25)</em> \u0437\u043D\u0430\u0447\u0435\u043D\u0438\u0435 <em>(artha\u1E25)</em> [\u043D\u0430\u0441\u0442\u043E\u044F\u0449\u0435\u0433\u043E] \u0430\u0444\u043E\u0440\u0438\u0437\u043C\u0430 <em>(s\u016Btra)</em> \u0431\u044B\u043B\u043E \u043F\u043E\u043A\u0430\u0437\u0430\u043D\u043E <em>(dar\u015Bita\u1E25)</em> \u044D\u0442\u043E\u0439 <em>(anena)</em> \u043F\u0430\u0440\u043E\u0439 <em>(dvayena)</em> k\u0101rik\u0101-s --\u0430\u0444\u043E\u0440\u0438\u0437\u043C\u043E\u0432-- <em>(k\u0101rik\u0101)</em> \u0432 Spandak\u0101rik\u0101-s <em>(spande)</em>.</p><blockquote><p>\u0423\u0445\u0432\u0430\u0442\u0438\u0432\u0448\u0438\u0441\u044C <em>(\u0101kramya)</em> \u0437\u0430 \u044D\u0442\u0443 <em>(tad)</em> \u0421\u0438\u043B\u0443 <em>(balam)</em>, Mantra-s <em>(mantr\u0101\u1E25... iti)</em>...|<br> [\u0421\u043C. Spandak\u0101rik\u0101-s II, 1 \u0438 2]</p></blockquote><p>||3||</p><hr><ol><li><p>\u0421\u043C\u043E\u0442\u0440\u0438\u0442\u0435 \u043F\u043E\u0441\u043B\u0435\u0434\u043D\u0438\u0439 \u0430\u0444\u043E\u0440\u0438\u0437\u043C \u041F\u0435\u0440\u0432\u043E\u0439 \u0413\u043B\u0430\u0432\u044B.</p></li><li><p>\u0421\u043E\u0441\u0442\u0430\u0432\u043D\u044B\u0435 \u0441\u043B\u043E\u0432\u0430 Bahuvr\u012Bhi \u044F\u0432\u043B\u044F\u044E\u0442\u0441\u044F \u0430\u0442\u0440\u0438\u0431\u0443\u0442\u0438\u0432\u043D\u044B\u043C\u0438. \u041A\u043E\u0433\u0434\u0430 \u043E\u043D\u0438 \u0440\u0430\u0437\u044A\u0435\u0434\u0438\u043D\u044F\u044E\u0442\u0441\u044F, \u0441\u043B\u043E\u0432\u043E &quot;yad&quot; (\u043A\u0430\u043A\u043E\u0439/\u043A\u0430\u043A\u0430\u044F/\u043A\u0430\u043A\u043E\u0435, \u043A\u043E\u0442\u043E\u0440\u044B\u0439/\u043A\u043E\u0442\u043E\u0440\u0430\u044F/\u043A\u043E\u0442\u043E\u0440\u043E\u0435, \u043A\u0442\u043E) \u043F\u043E\u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u0432 \u043B\u044E\u0431\u043E\u043C \u0432\u043E\u0437\u043C\u043E\u0436\u043D\u043E\u043C \u043F\u0430\u0434\u0435\u0436\u0435 (\u043A\u0440\u043E\u043C\u0435 Vocative - \u0417\u0432\u0430\u0442\u0435\u043B\u044C\u043D\u043E\u0433\u043E). \u0417\u0434\u0435\u0441\u044C, \u043E\u043D\u043E \u043F\u043E\u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u0432 \u0420\u043E\u0434\u0438\u0442\u0435\u043B\u044C\u043D\u043E\u043C \u043F\u0430\u0434\u0435\u0436\u0435 \u0435\u0434\u0438\u043D\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0433\u043E \u0447\u0438\u0441\u043B\u0430: yasya (\u043A\u0430\u043A\u043E\u0433\u043E/\u043A\u0430\u043A\u043E\u0439, \u043A\u043E\u0442\u043E\u0440\u043E\u0433\u043E/\u043A\u043E\u0442\u043E\u0440\u043E\u0439, \u043A\u043E\u0433\u043E, \u0447\u044C\u0435\u0433\u043E/\u0447\u044C\u0435\u0439). .</p></li><li><p>\u041D\u0435\u0441\u043C\u043E\u0442\u0440\u044F \u043D\u0430 \u043F\u043E\u0434\u0440\u043E\u0431\u043D\u043E\u0435 \u0442\u043E\u043B\u043A\u043E\u0432\u0430\u043D\u0438\u0435 K\u1E63emar\u0101ja, \u043A\u043E\u0442\u043E\u0440\u043E\u0435 \u043C\u043E\u0436\u0435\u0442 \u0441\u043C\u0443\u0442\u0438\u0442\u044C \u043D\u0435\u043A\u043E\u0442\u043E\u0440\u044B\u0445 \u043B\u044E\u0434\u0435\u0439, \u0443\u0447\u0435\u043D\u0438\u0435 \u043F\u043E\u043A\u0430\u0437\u044B\u0432\u0430\u0435\u0442 \u043F\u0440\u043E\u0441\u0442\u0443\u044E \u0432\u0435\u0449\u044C: \u0435\u0441\u043B\u0438 \u0432\u044B \u043F\u043E\u0432\u0442\u043E\u0440\u044F\u0435\u0442\u0435 \u043C\u0430\u043D\u0442\u0440\u0443, \u043D\u0435 \u043E\u0431\u0440\u0430\u0449\u0430\u044F \u0432\u043D\u0438\u043C\u0430\u043D\u0438\u044F \u043D\u0430 \u042F-\u0421\u043E\u0437\u043D\u0430\u043D\u0438\u0435, \u0438\u043B\u0438 \u015Aakti, \u0432\u0430\u0448\u0430 \u043C\u0430\u043D\u0442\u0440\u0430 \u043D\u0435 \u043F\u0440\u0438\u0432\u0435\u0434\u0435\u0442 \u0432\u0430\u0441 \u043A \u043A\u043E\u043D\u0435\u0447\u043D\u043E\u0439 \u0446\u0435\u043B\u0438, \u0442.\u0435. \u043A \u0432\u0430\u0448\u0435\u043C\u0443 \u0441\u043E\u0431\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u043C\u0443 \u0418\u0441\u0442\u0438\u043D\u043D\u043E\u043C\u0443 \u042F. \u0412\u043E\u0442 \u043F\u043E\u0447\u0435\u043C\u0443 \u044D\u0442\u043E \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u015A\u0101ktop\u0101ya (\u043C\u0435\u0442\u043E\u0434\u044B, \u043E\u0442\u043D\u043E\u0441\u044F\u0449\u0438\u0435\u0441\u044F \u043A \u015Aakti). \u0412 \u015A\u0101ktop\u0101ya \u043A\u043E\u043D\u0446\u0435\u043D\u0442\u0440\u0430\u0446\u0438\u044F \u0432\u0441\u0435\u0433\u0434\u0430 \u043E\u0441\u0443\u0449\u0435\u0441\u0442\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u043D\u0430 \u043A\u043E\u0440\u043D\u0435 \u043C\u0430\u043D\u0442\u0440\u044B, \u0442.\u0435. \u042F-\u0421\u043E\u0437\u043D\u0430\u043D\u0438\u0438, \u0430 \u043D\u0435 \u043D\u0430 \u0441\u0430\u043C\u043E\u0439 \u043C\u0430\u043D\u0442\u0440\u0435. \u041A\u043E\u043D\u0435\u0447\u043D\u043E, \u0432 \u043F\u0440\u043E\u0446\u0435\u0441\u0441\u0435 \u0441\u0432\u043E\u0435\u0439 \u043F\u0440\u0430\u043A\u0442\u0438\u043A\u0438 \u0432\u044B \u043F\u0440\u043E\u0439\u0434\u0435\u0442\u0435 \u0447\u0435\u0440\u0435\u0437 \u043C\u043D\u043E\u0433\u043E \u0444\u0430\u0437, \u043D\u043E \u0432 \u043A\u043E\u043D\u0446\u0435 \u0432\u0430\u0448\u0435 \u0432\u043D\u0438\u043C\u0430\u043D\u0438\u0435 \u0434\u043E\u043B\u0436\u043D\u043E \u043F\u0440\u0435\u0431\u044B\u0432\u0430\u0442\u044C \u043D\u0430 \u042F-\u0421\u043E\u0437\u043D\u0430\u043D\u0438\u0438 (\u015Aakti) \u0438\u043B\u0438 \u0432\u0430\u0448\u0430 \u043C\u0430\u043D\u0442\u0440\u0430 \u043D\u0435 \u0431\u0443\u0434\u0435\u0442 \u0443\u0441\u043F\u0435\u0448\u043D\u043E\u0439, \u043F\u043E\u0441\u043A\u043E\u043B\u044C\u043A\u0443 \u0422\u043E\u043B\u044C\u043A\u043E \u041E\u043D\u0430 \u043E\u0434\u043D\u0430 \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u0441\u0435\u043A\u0440\u0435\u0442\u043E\u043C \u043C\u0430\u043D\u0442\u0440. \u041E\u043D\u0430 \u0435\u0441\u0442\u044C \u0421\u0438\u043B\u0430, \u0434\u0430\u044E\u0449\u0430\u044F \u043D\u0430\u0447\u0430\u043B\u043E \u0432\u0441\u0435\u043C \u043C\u0430\u043D\u0442\u0440\u0430\u043C, \u0438 \u043D\u0435 \u043C\u043E\u0436\u0435\u0442 \u0431\u044B\u0442\u044C \u043D\u0438\u043A\u0430\u043A\u0438\u0445 \u0441\u043E\u043C\u043D\u0435\u043D\u0438\u0439 \u0432 \u044D\u0442\u043E\u043C! \u0422\u0430\u043A\u043E\u0432 \u0441\u043C\u044B\u0441\u043B.</p></li><li><p>\u0414\u043B\u044F \u043F\u043E\u043B\u0443\u0447\u0435\u043D\u0438\u044F \u0434\u043E\u043F\u043E\u043B\u043D\u0438\u0442\u0435\u043B\u044C\u043D\u043E\u0439 \u0438\u043D\u0444\u043E\u0440\u043C\u0430\u0446\u0438\u0438 \u043E M\u0101t\u1E5Bk\u0101, \u0447\u0438\u0442\u0430\u0439\u0442\u0435 \u0447\u0435\u0442\u0432\u0435\u0440\u0442\u044B\u0439 \u0430\u0444\u043E\u0440\u0438\u0437\u043C (\u0438 \u043A\u043E\u043C\u043C\u0435\u043D\u0442\u0430\u0440\u0438\u0438 \u043A \u043D\u0435\u043C\u0443) \u041F\u0435\u0440\u0432\u043E\u0439 \u0413\u043B\u0430\u0432\u044B.</p></li><li><p>\u0417\u043D\u0430\u0447\u0435\u043D\u0438\u044F \u043C\u043D\u043E\u0433\u0438\u0445 \u0432\u0435\u0449\u0435\u0439, \u0441\u043E\u0434\u0435\u0440\u0436\u0430\u0449\u0438\u0445\u0441\u044F \u0432 \u0446\u0438\u0442\u0430\u0442\u0435 \u044D\u0442\u043E\u0439 \u0422\u0430\u043D\u0442\u0440\u044B, \u044F\u0432\u043B\u044F\u044E\u0442\u0441\u044F \u043D\u0430\u0441\u0442\u043E\u043B\u044C\u043A\u043E \u0433\u043B\u0443\u0431\u043E\u043A\u0438\u043C\u0438 \u0438 \u0442\u0430\u0439\u043D\u044B\u043C\u0438, \u0447\u0442\u043E \u044F \u043F\u0440\u0438\u043D\u044F\u043B \u0440\u0435\u0448\u0435\u043D\u0438\u0435 \u043D\u0438\u043A\u0430\u043A \u043D\u0435 \u043A\u043E\u043C\u043C\u0435\u043D\u0442\u0438\u0440\u043E\u0432\u0430\u0442\u044C \u0438\u0445 \u0437\u0434\u0435\u0441\u044C \u0441 \u044D\u0442\u043E\u0433\u043E \u043C\u043E\u043C\u0435\u043D\u0442\u0430. \u042D\u0442\u043E \u043D\u0435\u043E\u0431\u0445\u043E\u0434\u0438\u043C\u043E \u043E\u0431\u044A\u044F\u0441\u043D\u0438\u0442\u044C \u043F\u043E\u0434\u0440\u043E\u0431\u043D\u043E \u0432 \u043C\u043E\u0438\u0445 \u0438\u0441\u0441\u043B\u0435\u0434\u043E\u0432\u0430\u043D\u0438\u044F\u0445 \u0432 \u0440\u0430\u0437\u0434\u0435\u043B\u0435 \u0422\u0440\u0438\u043A\u0430. \u041F\u0440\u0438\u0447\u0438\u043D\u0430 - \u043E\u0447\u0435\u043D\u044C \u043F\u0440\u043E\u0441\u0442\u0430: \u0435\u0441\u043B\u0438 \u0443 \u0432\u0430\u0441 \u043D\u0435\u0434\u043E\u0441\u0442\u0430\u0442\u043E\u0447\u043D\u043E &quot;\u0431\u0430\u0437\u043E\u0432\u044B\u0445&quot; \u0437\u043D\u0430\u043D\u0438\u0439 \u0438 \u043E\u043F\u044B\u0442\u0430 \u0432 \u044D\u0442\u043E\u043C \u043F\u0440\u0435\u0434\u043C\u0435\u0442\u0435 (cakra-s, ku\u1E47\u1E0Dalin\u012B, \u0438 \u0442.\u0434.), \u043A\u043E\u0440\u043E\u0442\u043A\u0438\u0435 \u043F\u043E\u044F\u0441\u043D\u0438\u0442\u0435\u043B\u044C\u043D\u044B\u0435 \u043F\u0440\u0438\u043C\u0435\u0447\u0430\u043D\u0438\u044F \u0442\u043E\u043B\u044C\u043A\u043E \u0432\u043D\u0435\u0441\u0443\u0442 \u0431\u043E\u043B\u044C\u0448\u0435 \u043F\u0443\u0442\u0430\u043D\u0438\u0446\u044B \u0438 \u043D\u0435\u043F\u0440\u0430\u0432\u0438\u043B\u044C\u043D\u043E\u0433\u043E \u043F\u043E\u043D\u0438\u043C\u0430\u043D\u0438\u044F. \u0410 \u0432\u043A\u043B\u044E\u0447\u0435\u043D\u0438\u0435 \u0441\u043B\u0438\u0448\u043A\u043E\u043C \u0434\u043B\u0438\u043D\u043D\u044B\u0445 \u043F\u043E\u044F\u0441\u043D\u0435\u043D\u0438\u0439 \u0437\u0434\u0435\u0441\u044C \u043F\u0440\u043E\u0441\u0442\u043E \u043D\u0435 \u043F\u0440\u0430\u043A\u0442\u0438\u0447\u043D\u043E. \u041A\u043E\u0433\u0434\u0430 \u0432\u044B \u043F\u0440\u043E\u0447\u0438\u0442\u0430\u0435\u0442\u0435 \u043E\u0441\u0442\u0430\u043B\u044C\u043D\u0443\u044E \u0447\u0430\u0441\u0442\u044C \u0446\u0438\u0442\u0438\u0440\u0443\u0435\u043C\u043E\u0433\u043E \u0442\u0435\u043A\u0441\u0442\u0430, \u0432\u044B \u044F\u0441\u043D\u0435\u0435 \u0443\u0432\u0438\u0434\u0438\u0442\u0435 \u043C\u043E\u044E \u0442\u043E\u0447\u043A\u0443 \u0437\u0440\u0435\u043D\u0438\u044F.</p></li><li><p>\u0417\u043D\u0430\u0447\u0435\u043D\u0438\u0435 M\u0101t\u1E5Bk\u0101 \u0438 M\u0101lin\u012B \u0431\u044B\u043B\u043E \u043A\u0440\u0430\u0442\u043A\u043E \u0440\u0430\u0437\u044A\u044F\u0441\u043D\u0435\u043D\u043E \u043C\u043D\u043E\u0439 \u0432 \u0442\u0440\u0435\u0442\u044C\u0435\u043C \u043F\u0440\u0438\u043C\u0435\u0447\u0430\u043D\u0438\u0438 \u043A I, 22.</p></li></ol></div>',1),s=[i];function p(k,u,v,n,d,h){return m(),e("div",null,s)}var o=a(r,[["render",p]]);export{b as __pageData,o as default};
